function setF(f,btn){activeFilter=f;document.querySelectorAll(".fb").forEach(function(b){b.classList.remove("active");});btn.classList.add("active");filterHostels();}
function filterHostels(){
  var q=(document.getElementById("hero-q").value||"").toLowerCase();
  var mp=parseInt(document.getElementById("hero-price").value)||999999;
  var sort=document.getElementById("sort-sel").value;
  var f=HOSTELS.filter(function(h){if(!h)return false;var mf=activeFilter==="all"||h.tags.indexOf(activeFilter)>=0;var ms=!q||h.name.toLowerCase().indexOf(q)>=0||h.area.toLowerCase().indexOf(q)>=0;return mf&&ms&&h.from<=mp;});
  if(sort==="price_asc")f.sort(function(a,b){return a.from-b.from;});
  else if(sort==="price_desc")f.sort(function(a,b){return b.from-a.from;});
  else if(sort==="rating")f.sort(function(a,b){return b.rating-a.rating;});
  document.getElementById("rc").textContent=f.length+" hostel"+(f.length!==1?"s":"")+" found";
  document.getElementById("hgrid").innerHTML=f.length?f.map(function(h){
    var inc=compareList.indexOf(h.id)>=0;
    return '<div class="hcard"><div class="ci" style="background:'+h.accentBg+'">'+h.emoji+(h.badge?'<div class="cbadge '+h.badge+'">'+h.badgeT+'</div>':'')+'<div class="cavail '+h.availS+'">'+h.avail+' beds free</div></div><div class="cbody"><div class="chdr"><div class="cname">'+h.name+'</div><div class="crat">'+stars(h.rating)+' '+h.rating+'</div></div><div class="cloc">\uD83D\uDCCD '+h.loc+'</div><div class="ctags">'+h.tagLbls.map(function(t){return '<span class="ctag">'+t+'</span>';}).join('')+'<span class="ctag">Est. '+h.est+'</span></div><div class="cpr"><div class="cprice">Rs. '+fmt(h.from)+' <span>/person/mo</span></div><div class="cacts"><button class="btn-view" onclick="showPage(\''+h.slug+'\')">View</button><button class="btn-apply" onclick="openApply('+h.id+')">Apply</button><button class="btn-wa" onclick="openWA('+h.id+')">\uD83D\uDCAC</button></div></div><div class="cmp-row"><label class="cmp-lbl"><input type="checkbox" '+(inc?"checked":"")+" onchange=\"toggleCompare("+h.id+',this)\" style="accent-color:var(--gold)"/> Compare</label></div></div></div>';
  }).join(''):'<div style="grid-column:1/-1;text-align:center;padding:60px;color:var(--muted)">\uD83D\uDD0D No hostels match your filters</div>';
}
function openWA(id){var h=HOSTELS.find(function(x){return x&&x.id===id;});if(!h)return;window.open("https://wa.me/"+h.wa+"?text="+encodeURIComponent("Assalam o Alaikum! I found "+h.name+" on LahoreBoysHostels. Interested in a room."),"_blank");}

// Compare
function toggleCompare(id,cb){if(cb.checked){if(compareList.length>=7){cb.checked=false;toast("Max 7");return;}compareList.push(id);}else{compareList=compareList.filter(function(x){return x!==id;});}updateCompareBar();filterHostels();}
function clearCompare(){compareList=[];updateCompareBar();filterHostels();}
function updateCompareBar(){
  var bar=document.getElementById("compare-bar");if(!compareList.length){bar.style.display="none";return;}
  bar.style.display="flex";var s="";
  for(var i=0;i<7;i++){if(i<compareList.length){var h=HOSTELS.find(function(x){return x&&x.id===compareList[i];});s+='<div class="cslot">'+(h?h.emoji+" "+h.short:"?")+'</div>';}else if(i<compareList.length+1)s+='<div class="cslot empty">+ Add</div>';}
  document.getElementById("cslots").innerHTML=s;
}
function openCompare(){
  if(compareList.length<2){toast("Select at least 2");return;}
  var hs=compareList.map(function(id){return HOSTELS.find(function(x){return x&&x.id===id;});}).filter(Boolean);
  var crit=[{l:"Price from",k:"from",f:function(v){return "Rs. "+fmt(v);},b:"min"},{l:"Rating",k:"rating",f:function(v){return v+"/5";},b:"max"},{l:"Capacity",k:"cap",f:function(v){return v;},b:null},{l:"Available",k:"avail",f:function(v){return v;},b:"max"},{l:"Est.",k:"est",f:function(v){return v;},b:null},{l:"Meals",k:"meals",f:function(v){return v?"Yes":"No";},b:null},{l:"WiFi",k:"wifi",f:function(v){return v?"Yes":"No";},b:null}];
  var cols=hs.map(function(h){return '<div class="cmp-col"><div class="cmp-col-hd"><h4>'+h.emoji+" "+h.name+'</h4><p>'+h.area+'</p></div>'+crit.map(function(c){var vals=hs.map(function(x){return x[c.k];});var best=c.b==="min"?h[c.k]===Math.min.apply(null,vals):c.b==="max"?h[c.k]===Math.max.apply(null,vals):false;return '<div class="crow"><span class="crow-lbl">'+c.l+'</span><span class="crow-val'+(best?" best":"")+'">'+c.f(h[c.k])+'</span></div>';}).join('')+'<div style="padding:9px 12px"><button class="btn-apply" style="width:100%;border-radius:5px" onclick="closeModal(\'compare\');showPage(\''+h.slug+'\')">View</button></div></div>';}).join('');
  document.getElementById("cmp-content").innerHTML='<div class="cmp-grid" style="grid-template-columns:repeat('+hs.length+',1fr)">'+cols+'</div>';
  document.getElementById("modal-compare").classList.add("open");
}

