function submitApply(){
  var name=document.getElementById("an").value.trim(),phone=document.getElementById("ap").value.trim(),occ=document.getElementById("ao").value,mi=document.getElementById("ami").value;
  if(!name||!phone||!occ||!mi){toast("Fill all required fields");return;}
  var h=currentApplyId?HOSTELS.find(function(x){return x&&x.id===currentApplyId;}):null;
  // Track application (Feature: admin analytics)
  if(currentApplyId)trackApplication(currentApplyId);
  addNotif("New application from "+name+" for "+(h?h.short:"Any hostel"),"admin");
  if(h){addNotif("New application: "+name,"manager");}
  var selectedH=document.getElementById("ah-apply")?document.getElementById("ah-apply").value:"";
  if(selectedH&&selectedH!=="general"){var sh=HOSTELS.find(function(x){return x&&x.id==selectedH;});if(sh){trackApplication(sh.id);addNotif("Application from "+name+" for "+sh.short,"manager");}}
  else{HOSTELS.filter(Boolean).forEach(function(hx){trackApplication(hx.id);});addNotif("General application from "+name,"admin");}
  var waNum=h?h.wa:(selectedH&&selectedH!=="general"?(HOSTELS.find(function(x){return x&&x.id==selectedH;})||{}).wa:"923081112269")||"923081112269";
  var msg="Assalam o Alaikum!\nApplication via LahoreBoysHostels\nHostel: "+(h?h.name:"Any")+"\nName: "+name+"\nPhone: "+phone+"\nOccupation: "+occ+"\nMove-In: "+mi;
  document.getElementById("am-body").innerHTML='<div class="success-state"><div class="s-icon">\u2705</div><div class="s-title">Application Submitted!</div><div class="s-sub">The hostel will contact you within 24 hours on '+phone+'.</div></div>';
  document.getElementById("am-foot").innerHTML='<button class="bsubmit" onclick="window.open(\'https://wa.me/'+waNum+'?text='+encodeURIComponent(msg)+'\',\'_blank\');closeModal(\'apply\')">\uD83D\uDCAC WhatsApp</button><button class="bcancel" onclick="closeModal(\'apply\')">Close</button>';
  toast("Application submitted!");
}
