var loginRole="manager";
function setLoginRole(r){
  loginRole=r;
  document.querySelectorAll(".l-tab").forEach(function(b){b.classList.toggle("active",b.dataset.role===r);});
  var hints={manager:"Manager login",hostelite:"Hostelite login \u2014 credentials from your manager",staff:"Staff login \u2014 credentials from your manager",finance:"Finance department login",admin:"Platform admin login"};
  document.getElementById("l-hint").textContent=hints[r]||"";
  var demos={manager:'Demo: <code style="color:#E8A84B;background:#1E2636;padding:1px 5px;border-radius:3px">manager.ar</code> / <code style="color:#E8A84B;background:#1E2636;padding:1px 5px;border-radius:3px">ar2024</code>',hostelite:"Credentials from your manager",staff:"Credentials from your manager",finance:'<code style="color:#E8A84B;background:#1E2636;padding:1px 5px;border-radius:3px">finance.lbh</code> / <code style="color:#E8A84B;background:#1E2636;padding:1px 5px;border-radius:3px">finance@2025</code>',admin:'<code style="color:#E8A84B;background:#1E2636;padding:1px 5px;border-radius:3px">admin.lbh</code> / <code style="color:#E8A84B;background:#1E2636;padding:1px 5px;border-radius:3px">lbh@admin2025</code>'};
  document.getElementById("l-demo").innerHTML=demos[r]||"";
}
function doLogin(){
  var u=document.getElementById("l-user").value.trim(),p=document.getElementById("l-pass").value.trim();
  var err=document.getElementById("l-err");
  if(!u||!p){err.textContent="Enter username and password.";err.style.display="block";return;}
  // Admin
  if(u==="admin.lbh"&&p==="lbh@admin2025"){currentUser={role:"admin",name:"Platform Admin",user:u};err.style.display="none";document.getElementById("l-pass").value="";resetSession();showPortalView("admin");
    // Log admin activity
    var al=dbGet("admin_logins");al.push({user:u,time:new Date().toISOString()});dbSet("admin_logins",al.slice(-100));
    return;}
  // Finance
  if(loginRole==="finance"||u==="finance.lbh"){
    if(u==="finance.lbh"&&p==="finance@2025"){currentUser={role:"finance",name:"Finance Dept",user:u};err.style.display="none";document.getElementById("l-pass").value="";resetSession();showPortalView("finance");return;}
    err.textContent="Invalid finance credentials.";err.style.display="block";return;
  }
  // Manager
  if(loginRole==="manager"){
    var acc=MGRS.find(function(a){return a.user===u&&a.pass===p;});
    if(!acc){err.textContent="Invalid credentials.";err.style.display="block";return;}
    initRooms(acc.hid);
    currentUser={role:"manager",hid:acc.hid,name:acc.name,user:acc.user,pass:acc.pass};
    // Log manager activity (Feature 3: audit)
    var ml=dbGet("mgr_logins");ml.push({user:u,hid:acc.hid,time:new Date().toISOString()});dbSet("mgr_logins",ml.slice(-200));
  }
  // Hostelite
  else if(loginRole==="hostelite"){
    var found=false;
    for(var i=0;i<HOSTELS.length;i++){
      if(!HOSTELS[i])continue;var hid=HOSTELS[i].id;
      var accs=dbGetO(hk(hid,"taccs"));
      if(accs[u]&&accs[u].pass===p){var a=accs[u];currentUser={role:"hostelite",hid:hid,tid:a.tid,name:a.name,user:u};found=true;break;}
    }
    if(!found){err.textContent="Invalid credentials.";err.style.display="block";return;}
  }
  // Staff
  else if(loginRole==="staff"){
    var found2=false;
    for(var j=0;j<HOSTELS.length;j++){
      if(!HOSTELS[j])continue;var hid2=HOSTELS[j].id;
      var saccs=dbGetO(hk(hid2,"staffaccs"));
      if(saccs[u]&&saccs[u].pass===p){var sa=saccs[u];currentUser={role:"staff",hid:hid2,name:sa.name,staffRole:sa.role,staffId:sa.staffId,user:u};found2=true;break;}
    }
    if(!found2){err.textContent="Invalid staff credentials.";err.style.display="block";return;}
  }
  err.style.display="none";document.getElementById("l-pass").value="";resetSession();
  var viewMap={manager:"manager",hostelite:"hostelite",admin:"admin",staff:"staffportal",finance:"finance"};
  showPortalView(viewMap[currentUser.role]||currentUser.role);
}
function showPortalView(v){
  ["portal-login","portal-manager","portal-hostelite","portal-admin","portal-staff","portal-finance"].forEach(function(id){var el=document.getElementById(id);if(el)el.style.display="none";});
  var target=v==="staffportal"?"staff":v;
  var el=document.getElementById("portal-"+target);
  if(el)el.style.display="flex";
  if(v==="manager")renderMgrDash();
  if(v==="hostelite")renderHtDash();
  if(v==="admin")renderAdminDash();
  if(v==="staffportal")renderStaffPortal();
  if(v==="finance")renderFinancePortal();
}
function logout(){currentUser=null;clearTimeout(sessionTimer);showPortalView("login");}

