// ÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚Â
function renderAdminDash(){
  if(!currentUser||currentUser.role!=="admin")return;
  // Groups (Feature 1 modified)
  var groups=dbGet("hostel_groups");
  var pendReqs=dbGet("group_requests").filter(function(r){return r.status==="pending";});
  // Application analytics
  var apps=dbGet("applications");
  var now=new Date();
  var todayApps=apps.filter(function(a){return a.date&&a.date.substring(0,10)===today();}).length;
  var weekApps=apps.filter(function(a){return a.date&&(now-new Date(a.date))<7*86400000;}).length;
  var monthApps=apps.filter(function(a){return a.date&&a.date.substring(0,7)===curM();}).length;
  var yearApps=apps.filter(function(a){return a.date&&a.date.substring(0,4)===String(now.getFullYear());}).length;
  var totalHostels=HOSTELS.filter(Boolean).length;
  // Stats
  document.getElementById("ad-stats").innerHTML=""
    +'<div class="stat-card" style="--accent:var(--p-blue)"><div class="slabel">Total Hostels</div><div class="sval">'+totalHostels+'</div></div>'
    +'<div class="stat-card" style="--accent:var(--p-green)"><div class="slabel">Groups</div><div class="sval">'+groups.length+'</div></div>'
    +'<div class="stat-card" style="--accent:var(--gold)"><div class="slabel">Apps Today</div><div class="sval">'+todayApps+'</div><div class="ssub">Week: '+weekApps+' \u00B7 Month: '+monthApps+'</div></div>'
    +'<div class="stat-card" style="--accent:var(--p-orange)"><div class="slabel">Apps This Year</div><div class="sval">'+yearApps+'</div></div>'
    +(pendReqs.length?'<div class="stat-card" style="--accent:var(--p-red)"><div class="slabel">Pending Requests</div><div class="sval">'+pendReqs.length+'</div></div>':'');

  // Manager audit log (Feature 3)
  var mgrLogins=dbGet("mgr_logins").slice(-20).reverse();
  document.getElementById("ad-audit").innerHTML=mgrLogins.length?mgrLogins.map(function(l){
    var h=HOSTELS.find(function(x){return x&&x.id===l.hid;});
    return '<div class="oi"><div><div style="font-weight:600;font-size:.83rem">'+l.user+'</div><div style="font-size:.72rem;color:var(--muted)">'+(h?h.short:"?")+'</div></div><span style="font-size:.72rem;color:var(--muted);font-family:var(--mono)">'+new Date(l.time).toLocaleString("en-PK",{day:"2-digit",month:"short",year:"numeric",hour:"2-digit",minute:"2-digit"})+'</span></div>';
  }).join(''):'<div style="text-align:center;padding:20px;color:var(--muted)">No logins recorded</div>';

  // Hostel list with health scores (Feature 7)
  document.getElementById("admin-hostel-list").innerHTML=HOSTELS.filter(Boolean).map(function(h,idx){
    var acc=MGRS.find(function(a){return a.hid===h.id;});
    var score=calcHealthScore(h.id);
    var scoreClass=score>=70?"health-good":score>=40?"health-ok":"health-bad";
    var group=groups.find(function(g){return g.hostels&&g.hostels.indexOf(h.id)>=0;});
    var TAGS=["featured","verified","premium","new"];
    var tagHtml=TAGS.map(function(tag){return '<span class="admin-tag'+(h.badge===tag?" active":"")+'" onclick="adminToggleTag('+h.id+',\''+tag+'\')">'+tag+'</span>';}).join('');
    return '<div class="mcard" draggable="true" ondragstart="adminDragStart(event,'+idx+')" ondragover="adminDragOver(event)" ondrop="adminDrop(event,'+idx+')" style="cursor:grab"><div class="mcard-hdr"><div style="flex:1"><div style="font-weight:600;font-size:.88rem">'+h.emoji+' '+h.name+(group?' <span class="badge bb" style="font-size:.6rem">'+group.name+'</span>':'')+'</div><div style="font-size:.73rem;color:var(--muted);margin-top:3px">'+h.area+' \u00B7 Rs. '+fmt(h.from)+'/mo \u00B7 <code style="color:#E8A84B;background:#1E2636;padding:1px 5px;border-radius:3px">'+(acc?acc.user+'/'+acc.pass:'?')+'</code></div><div style="margin-top:4px">'+tagHtml+'</div><div class="health-bar"><div class="health-fill '+scoreClass+'" style="width:'+score+'%"></div></div><div style="font-size:.68rem;color:var(--muted)">Health: '+score+'/100</div></div><div style="display:flex;gap:5px;flex-wrap:wrap;flex-shrink:0"><button class="btn btn-blue btn-sm" onclick="adminEditHostel('+h.id+')">Edit</button><button class="btn btn-out btn-sm" onclick="adminManageImages('+h.id+')">Images</button>'+(h.isCustom?'<button class="btn btn-red btn-sm" onclick="adminRemoveHostel('+h.id+')">Remove</button>':'')+'</div></div></div>';
  }).join('');

  // Groups section
  document.getElementById("ad-groups").innerHTML=groups.length?groups.map(function(g){
    var gHostels=HOSTELS.filter(function(h){return h&&g.hostels&&g.hostels.indexOf(h.id)>=0;});
    return '<div class="mcard"><div class="mcard-hdr"><div><div style="font-weight:600">'+g.name+'</div><div style="font-size:.73rem;color:var(--muted)">'+gHostels.length+' hostel(s) \u00B7 Owner: '+g.owner+'</div></div><div style="display:flex;gap:5px"><button class="btn btn-out btn-sm" onclick="adminEditGroup(\''+g.id+'\')">Edit</button><button class="btn btn-red btn-sm" onclick="adminDelGroup(\''+g.id+'\')">Delete</button></div></div><div style="display:flex;gap:4px;flex-wrap:wrap;margin-top:6px">'+gHostels.map(function(h){return '<span class="badge bb">'+h.emoji+' '+h.short+'</span>';}).join('')+'</div></div>';
  }).join(''):'<div style="text-align:center;padding:30px;color:var(--muted)">No groups created yet</div>';

  // Pending requests
  document.getElementById("ad-requests").innerHTML=pendReqs.length?pendReqs.map(function(r){
    return '<div class="mcard"><div class="mcard-hdr"><div><div style="font-weight:600">'+r.hostelName+' \u2192 Group: '+(groups.find(function(g){return g.id===r.groupId;})||{}).name+'</div><div style="font-size:.73rem;color:var(--muted)">Requested by: '+r.requestedBy+' \u00B7 '+fdate(r.date)+'</div></div><div style="display:flex;gap:5px"><button class="btn btn-grn btn-sm" onclick="adminApproveReq(\''+r.id+'\')">Approve</button><button class="btn btn-red btn-sm" onclick="adminRejectReq(\''+r.id+'\')">Reject</button></div></div></div>';
  }).join(''):'<div style="text-align:center;padding:20px;color:var(--muted)">No pending requests</div>';

  // Application analytics chart (simple bar)
  renderAdminAnalytics();
}

function renderAdminAnalytics(){
  var apps=dbGet("applications");var el=document.getElementById("ad-analytics");if(!el)return;
  var now=new Date();
  // Last 12 months
  var months=[];
  for(var i=11;i>=0;i--){
    var d=new Date(now.getFullYear(),now.getMonth()-i,1);
    var ym=d.getFullYear()+"-"+String(d.getMonth()+1).padStart(2,"0");
    var count=apps.filter(function(a){return a.date&&a.date.substring(0,7)===ym;}).length;
    months.push({label:new Date(d).toLocaleDateString("en-PK",{month:"short",year:"2-digit"}),count:count});
  }
  var max=Math.max.apply(null,months.map(function(m){return m.count;}))||1;
  el.innerHTML='<div style="display:flex;align-items:flex-end;gap:6px;height:140px;padding:8px 0">'+months.map(function(m){
    var h=Math.max(4,Math.round(m.count/max*120));
    return '<div style="flex:1;text-align:center"><div style="background:var(--gold);border-radius:3px 3px 0 0;height:'+h+'px;margin:0 auto;width:100%;max-width:36px" title="'+m.count+' apps"></div><div style="font-size:.62rem;color:var(--muted);margin-top:4px;white-space:nowrap">'+m.label+'</div></div>';
  }).join('')+'</div><div style="font-size:.72rem;color:var(--muted);text-align:center;margin-top:4px">Applications per month (last 12 months)</div>';

  // Per-hostel breakdown
  var perHostel=HOSTELS.filter(Boolean).map(function(h){
    var c=apps.filter(function(a){return a.hid===h.id;}).length;
    return {name:h.short,count:c,emoji:h.emoji};
  }).sort(function(a,b){return b.count-a.count;});
  document.getElementById("ad-per-hostel").innerHTML=perHostel.map(function(h){
    return '<div class="oi"><div style="font-weight:600;font-size:.83rem">'+h.emoji+' '+h.name+'</div><span style="font-family:var(--mono);color:var(--gold)">'+h.count+' apps</span></div>';
  }).join('');
}

// Groups CRUD
function adminAddGroup(){
  var name=document.getElementById("ag-name").value.trim();
  var owner=document.getElementById("ag-owner").value.trim();
  if(!name||!owner){mToast("Name and owner required","err");return;}
  var groups=dbGet("hostel_groups");
  groups.push({id:dbId(),name:name,owner:owner,hostels:[],createdOn:today()});
  dbSet("hostel_groups",groups);
  document.getElementById("ag-name").value="";document.getElementById("ag-owner").value="";
  closeMM("add-group");mToast("Group created","ok");renderAdminDash();
}
function adminEditGroup(gid){
  var groups=dbGet("hostel_groups");var g=groups.find(function(x){return x.id===gid;});if(!g)return;
  // Show edit modal with hostel assignment
  var allH=HOSTELS.filter(Boolean);
  document.getElementById("aeg-id").value=gid;
  document.getElementById("aeg-name").value=g.name;
  document.getElementById("aeg-owner").value=g.owner;
  document.getElementById("aeg-hostels").innerHTML=allH.map(function(h){
    var checked=g.hostels&&g.hostels.indexOf(h.id)>=0;
    return '<label style="display:flex;align-items:center;gap:6px;padding:5px 0;font-size:.82rem;color:var(--text);border-bottom:1px solid var(--bd)"><input type="checkbox" value="'+h.id+'"'+(checked?" checked":"")+' style="accent-color:var(--gold)"/> '+h.emoji+' '+h.name+'</label>';
  }).join('');
  openMM("edit-group");
}
function adminSaveGroup(){
  var gid=document.getElementById("aeg-id").value;
  var groups=dbGet("hostel_groups");var g=groups.find(function(x){return x.id===gid;});if(!g)return;
  g.name=document.getElementById("aeg-name").value.trim();
  g.owner=document.getElementById("aeg-owner").value.trim();
  g.hostels=[];
  document.querySelectorAll("#aeg-hostels input:checked").forEach(function(cb){g.hostels.push(parseInt(cb.value)||cb.value);});
  dbSet("hostel_groups",groups);closeMM("edit-group");mToast("Group updated","ok");renderAdminDash();
}
function adminDelGroup(gid){if(!confirm("Delete this group?"))return;dbSet("hostel_groups",dbGet("hostel_groups").filter(function(g){return g.id!==gid;}));mToast("Deleted","ok");renderAdminDash();}
function adminApproveReq(rid){
  var reqs=dbGet("group_requests");var r=reqs.find(function(x){return x.id===rid;});if(!r)return;
  r.status="approved";
  // Add hostel to group
  var groups=dbGet("hostel_groups");var g=groups.find(function(x){return x.id===r.groupId;});
  if(g){if(!g.hostels)g.hostels=[];if(g.hostels.indexOf(r.hostelId)<0)g.hostels.push(r.hostelId);dbSet("hostel_groups",groups);}
  dbSet("group_requests",reqs);addNotif("Hostel "+r.hostelName+" approved for group","manager");mToast("Approved","ok");renderAdminDash();
}
function adminRejectReq(rid){
  var reqs=dbGet("group_requests");var r=reqs.find(function(x){return x.id===rid;});if(!r)return;
  r.status="rejected";dbSet("group_requests",reqs);mToast("Rejected","ok");renderAdminDash();
}
// Broadcast notice (Feature 4)
function adminBroadcast(){
  var title=document.getElementById("ab-title").value.trim();
  var body=document.getElementById("ab-body").value.trim();
  if(!title||!body){mToast("Fill title and body","err");return;}
  HOSTELS.filter(Boolean).forEach(function(h){
    var arr=dbGet(hk(h.id,"notices"));
    arr.unshift({id:dbId(),title:"[ADMIN] "+title,body:body,cat:"Urgent",pinned:1,date:today(),fromAdmin:true});
    dbSet(hk(h.id,"notices"),arr);
  });
  addNotif("Broadcast: "+title,"all");
  closeMM("broadcast");document.getElementById("ab-title").value="";document.getElementById("ab-body").value="";
  mToast("Broadcast sent to all hostels","ok");renderAdminDash();
}
// Manager account management (Feature 5)
function adminResetMgrPwd(){
  var sel=document.getElementById("arm-sel").value;
  var acc=MGRS.find(function(a){return a.user===sel;});if(!acc){mToast("Select a manager","err");return;}
  var newPwd="mgr"+String(Math.floor(1000+Math.random()*9000));
  acc.pass=newPwd;
  document.getElementById("arm-result").innerHTML='<div class="hint-box">Password reset for '+acc.name+': <code style="color:#3DD68C">'+newPwd+'</code></div>';
  mToast("Password reset","ok");
}
// Drag reorder
var adminDragIdx=null;
function adminDragStart(e,idx){adminDragIdx=idx;e.dataTransfer.effectAllowed="move";}
function adminDragOver(e){e.preventDefault();e.currentTarget.classList.add("drag-over");}
function adminDrop(e,dropIdx){e.preventDefault();e.currentTarget.classList.remove("drag-over");if(adminDragIdx===null||adminDragIdx===dropIdx)return;var item=HOSTELS.splice(adminDragIdx,1)[0];HOSTELS.splice(dropIdx,0,item);buildHostelPages();filterHostels();renderAdminDash();mToast("Reordered","ok");}
function adminToggleTag(hid,tag){var h=HOSTELS.find(function(x){return x&&x.id===hid;});if(!h)return;
  if(!h.badges)h.badges=h.badge?[h.badge]:[];
  var idx=h.badges.indexOf(tag);
  if(idx>=0)h.badges.splice(idx,1);else h.badges.push(tag);
  h.badge=h.badges[0]||null;h.badgeT=h.badge?(h.badge.charAt(0).toUpperCase()+h.badge.slice(1)):null;
  buildHostelPages();filterHostels();renderAdminDash();}
// Edit hostel
function adminEditHostel(hid){
  var h=HOSTELS.find(function(x){return x&&x.id===hid;});if(!h)return;
  document.getElementById("ae-hid").value=hid;
  document.getElementById("ae-name").value=h.name;document.getElementById("ae-area").value=h.area;
  document.getElementById("ae-loc").value=h.loc;document.getElementById("ae-from").value=h.from;
  document.getElementById("ae-cap").value=h.cap;document.getElementById("ae-avail").value=h.avail;
  document.getElementById("ae-rating").value=h.rating;document.getElementById("ae-phone").value=h.phone;
  document.getElementById("ae-owner").value=h.owner;document.getElementById("ae-desc").value=h.desc;
  openMM("edit-hostel");
}
function adminSaveEdit(){
  var hid=parseInt(document.getElementById("ae-hid").value)||document.getElementById("ae-hid").value;
  var h=HOSTELS.find(function(x){return x&&x.id==hid;});if(!h)return;
  h.name=document.getElementById("ae-name").value.trim()||h.name;h.short=h.name.split(" ").slice(0,2).join(" ");
  h.area=document.getElementById("ae-area").value.trim()||h.area;h.loc=document.getElementById("ae-loc").value.trim()||h.loc;
  h.from=parseInt(document.getElementById("ae-from").value)||h.from;h.cap=parseInt(document.getElementById("ae-cap").value)||h.cap;
  h.avail=parseInt(document.getElementById("ae-avail").value)||h.avail;h.rating=parseFloat(document.getElementById("ae-rating").value)||h.rating;
  h.phone=document.getElementById("ae-phone").value.trim()||h.phone;h.owner=document.getElementById("ae-owner").value.trim()||h.owner;
  h.desc=document.getElementById("ae-desc").value.trim()||h.desc;
  buildHostelPages();filterHostels();closeMM("edit-hostel");renderAdminDash();mToast("Updated","ok");
}
// Image management
function adminManageImages(hid){
  var imgs=JSON.parse(localStorage.getItem("lbh_images_"+hid)||"[]");
  document.getElementById("ai-hid").value=hid;
  var h=HOSTELS.find(function(x){return x&&x.id===hid;});
  document.getElementById("ai-hname").textContent=h?h.name:"";
  document.getElementById("ai-list").innerHTML=imgs.length?imgs.map(function(url,i){return '<div style="display:flex;gap:8px;align-items:center;margin-bottom:6px"><img src="'+url+'" style="width:80px;height:50px;object-fit:cover;border-radius:4px" onerror="this.style.display=\'none\'"/><input class="mfi" value="'+url+'" style="flex:1" onchange="adminUpdateImg('+hid+','+i+',this.value)"/><button class="btn btn-red btn-sm" onclick="adminDelImg('+hid+','+i+')">x</button></div>';}).join(''):'<div style="color:var(--muted);font-size:.82rem;padding:12px 0">No images. Add URLs below.</div>';
  openMM("manage-images");
}
function adminAddImg(hid){var url=document.getElementById("ai-url").value.trim();if(!url)return;var imgs=JSON.parse(localStorage.getItem("lbh_images_"+hid)||"[]");imgs.push(url);localStorage.setItem("lbh_images_"+hid,JSON.stringify(imgs));document.getElementById("ai-url").value="";adminManageImages(hid);}
function adminDelImg(hid,idx){var imgs=JSON.parse(localStorage.getItem("lbh_images_"+hid)||"[]");imgs.splice(idx,1);localStorage.setItem("lbh_images_"+hid,JSON.stringify(imgs));adminManageImages(hid);}
function adminUpdateImg(hid,idx,val){var imgs=JSON.parse(localStorage.getItem("lbh_images_"+hid)||"[]");imgs[idx]=val;localStorage.setItem("lbh_images_"+hid,JSON.stringify(imgs));}
function adminRemoveHostel(id){if(!confirm("Remove?"))return;var saved=JSON.parse(localStorage.getItem("lbh_custom_hostels")||"[]");saved=saved.filter(function(h){return h.id!==id;});localStorage.setItem("lbh_custom_hostels",JSON.stringify(saved));var idx=HOSTELS.findIndex(function(h){return h&&h.id===id;});if(idx>-1)HOSTELS.splice(idx,1);buildHostelPages();filterHostels();renderAdminDash();}
function adminAddHostel(){
  var name=document.getElementById("ah-name").value.trim(),area=document.getElementById("ah-area").value.trim(),from=parseInt(document.getElementById("ah-from").value)||6500,owner=document.getElementById("ah-owner").value.trim(),phone=document.getElementById("ah-phone").value.trim(),mgUser=document.getElementById("ah-user").value.trim(),mgPass=document.getElementById("ah-pass").value.trim();
  if(!name||!area||!owner||!mgUser||!mgPass){mToast("Fill required fields","err");return;}
  var saved=JSON.parse(localStorage.getItem("lbh_custom_hostels")||"[]");var newId=Date.now();
  var pfx=(name.split(" ").map(function(w){return w[0]||"";}).join("").toUpperCase()+"00").substring(0,3);
  var newH={id:newId,slug:"h"+newId,name:name,short:name.split(" ").slice(0,2).join(" "),area:area,loc:area+", Lahore",emoji:"\uD83C\uDFE0",accentBg:"#0F1923",accentC:"#E8A84B",badge:null,badgeT:null,rating:4.0,reviews:0,est:new Date().getFullYear(),yrs:0,cap:40,avail:10,availS:"available",from:from,bldg:"",phone:phone,wa:phone.replace(/[^0-9]/g,""),owner:owner,owner2:null,phone2:null,wa2:null,tags:["student","professional"],tagLbls:["Students","Professionals"],meals:false,wifi:true,mapQ:area.replace(/ /g,"+")+"Lahore",amenities:[["\uD83D\uDCF1","WiFi"],["\uD83D\uDEBF","Bathrooms"],["\uD83D\uDCA1","Bills Included"]],rooms:[{type:"Sharing",count:"Standard",price:from,feats:["WiFi","Bills included"]}],desc:name+" in "+area+".",about:name+" in "+area+", Lahore.",hls:[["Quality","In "+area+"."]],mgUser:mgUser,mgPass:mgPass,prefix:pfx,isCustom:true};
  saved.push(newH);localStorage.setItem("lbh_custom_hostels",JSON.stringify(saved));
  HOSTELS.push(newH);MGRS.push({hid:newId,user:mgUser,pass:mgPass,name:owner});HPFX[newId]=pfx;RCFG[newId]=[[4,10]];
  ["ah-name","ah-area","ah-owner","ah-phone","ah-user","ah-pass","ah-from"].forEach(function(id){document.getElementById(id).value="";});
  document.getElementById("ah-result").innerHTML='<div class="hint-box">Added! Login: <strong>'+mgUser+'</strong> / <strong>'+mgPass+'</strong></div>';
  buildHostelPages();filterHostels();renderAdminDash();
}
// Export (Feature 6)
function adminExportCSV(){
  var rows=["Hostel,Area,Capacity,Avail,Rating,Price From,Owner,Phone"];
  HOSTELS.filter(Boolean).forEach(function(h){rows.push([h.name,h.area,h.cap,h.avail,h.rating,h.from,h.owner,h.phone].join(","));});
  var blob=new Blob([rows.join("\n")],{type:"text/csv"});
  var url=URL.createObjectURL(blob);var a=document.createElement("a");a.href=url;a.download="lbh_hostels_"+today()+".csv";a.click();
  mToast("Exported","ok");
}

