function renderMgrDash(){
  if(!currentUser||currentUser.role!=="manager")return;
  var h=HOSTELS.find(function(x){return x&&x.id===currentUser.hid;});
  document.getElementById("m-hname").textContent=h?h.name:"Hostel";
  document.getElementById("m-uname").textContent=currentUser.name;
  initRooms(currentUser.hid);mInitMonthSel();mPopLedgerSel2();mPopStaffSel();
  switchMTab("dashboard");
}
function switchMTab(tab){
  mTab=tab;
  document.querySelectorAll(".mtab").forEach(function(b){b.classList.toggle("active",b.dataset.tab===tab);});
  var panels=["dashboard","tenants","rooms","payments","ledger","maintenance","notices","documents","staff","expenses","bills","visitors","attendance","staffclock","website","settings"];
  panels.forEach(function(p){var el=document.getElementById("mp-"+p);if(el)el.style.display=p===tab?"block":"none";});
  if(tab==="dashboard")renderMDash();if(tab==="tenants")renderMTenants();if(tab==="rooms")renderMRooms();
  if(tab==="payments"){mInitMonthSel();switchPTab("monthly");renderMPayments();}
  if(tab==="ledger"){mPopLedgerSel2();renderMLedger2();}
  if(tab==="maintenance")renderMMaint();if(tab==="notices")renderMNotices();if(tab==="documents")renderMDocs();
  if(tab==="staff")renderMStaff();if(tab==="expenses"){initExpMonthSel();renderMExpenses();}
  if(tab==="bills")renderMBills();if(tab==="visitors")renderMVisitors();if(tab==="attendance")renderMAttendance();
  if(tab==="staffclock")renderMStaffClock();
  if(tab==="website")renderMWebsite();
  if(tab==="settings")renderMSettings();
}

// ÃƒÂ¢Ã¢â‚¬ÂÃ¢â€šÂ¬ÃƒÂ¢Ã¢â‚¬ÂÃ¢â€šÂ¬ÃƒÂ¢Ã¢â‚¬ÂÃ¢â€šÂ¬ DASHBOARD ÃƒÂ¢Ã¢â‚¬ÂÃ¢â€šÂ¬ÃƒÂ¢Ã¢â‚¬ÂÃ¢â€šÂ¬ÃƒÂ¢Ã¢â‚¬ÂÃ¢â€šÂ¬
function renderMDash(){
  var hid=currentUser.hid;var tenants=dbGet(hk(hid,"tenants")).filter(function(t){return t.status==="active";});
  var rooms=dbGet(hk(hid,"rooms"));var allPay=dbGet(hk(hid,"pays"));var curPay=allPay.filter(function(p){return p.month===curM();});
  var issues=dbGet(hk(hid,"maint")).filter(function(i){return i.status!=="resolved";});
  var totalBeds=rooms.reduce(function(s,r){return s+r.cap;},0);var occ=Math.round(tenants.length/(totalBeds||1)*100);
  var rev=curPay.filter(function(p){return p.status==="paid";}).reduce(function(s,p){return s+p.amount;},0);
  var potRev=tenants.reduce(function(s,t){return s+t.rent;},0);
  var expenses=dbGet(hk(hid,"expenses")).filter(function(x){return (x.date||"").substring(0,7)===curM();});
  var totalExp2=expenses.reduce(function(s,x){return s+x.amount;},0);var netProfit=rev-totalExp2;
  // Health score
  var score=calcHealthScore(hid);var scoreClass=score>=70?"health-good":score>=40?"health-ok":"health-bad";
  document.getElementById("d-stats").innerHTML=""
    +'<div class="stat-card" style="--accent:var(--p-blue)"><div class="slabel">Active Tenants</div><div class="sval">'+tenants.length+'</div><div class="ssub">of '+totalBeds+' beds</div></div>'
    +'<div class="stat-card" style="--accent:var(--p-green)"><div class="slabel">Occupancy</div><div class="sval">'+occ+'%</div></div>'
    +'<div class="stat-card" style="--accent:var(--gold)"><div class="slabel">Revenue</div><div class="sval" style="font-size:1.1rem">Rs. '+mFmt(rev)+'</div><div class="ssub">of Rs. '+mFmt(potRev)+'</div></div>'
    +'<div class="stat-card" style="--accent:var(--p-orange)"><div class="slabel">Open Issues</div><div class="sval">'+issues.length+'</div></div>'
    +'<div class="stat-card" style="--accent:'+(netProfit>=0?"var(--p-green)":"var(--p-red)")+'"><div class="slabel">Net P/L</div><div class="sval" style="font-size:1.1rem">'+(netProfit>=0?"+":"")+'Rs. '+mFmt(netProfit)+'</div></div>';

  // Overdue
  var paidIds={};curPay.filter(function(p){return p.status==="paid";}).forEach(function(p){paidIds[p.tid]=true;});
  var overdue=tenants.filter(function(t){return !paidIds[t.id];});
  // Late fee config (Feature 19)
  var lateFee=parseInt(dbGetO(hk(hid,"config")).lateFee)||0;
  var lateDay=parseInt(dbGetO(hk(hid,"config")).lateDay)||10;
  var dayOfMonth=new Date().getDate();
  document.getElementById("d-overdue").innerHTML=overdue.length?overdue.map(function(t){
    var rm=rooms.find(function(r){return r.id===t.room;});
    var lateAmt=(lateFee&&dayOfMonth>lateDay&&!dbGetO(hk(hid,"late_waived"))[t.id+curM()])?lateFee:0;
    return '<div class="oi"><div><div style="font-weight:600">'+t.name+(lateAmt?' <span class="badge br" style="font-size:.6rem">+Rs. '+mFmt(lateAmt)+' late fee</span>':'')+'</div><div style="font-size:.73rem;color:var(--muted)"><span class="m-tid">'+t.tid+'</span>'+(rm?' \u00B7 '+rm.num:'')+'</div></div><div style="display:flex;gap:5px;align-items:center"><span style="color:var(--p-red);font-family:var(--mono)">Rs. '+mFmt(t.rent+lateAmt)+'</span>'+(lateAmt?'<button class="btn btn-out btn-sm" onclick="mWaiveLateFee(\''+t.id+'\')">Waive</button>':'')+'<button class="btn btn-grn btn-sm" onclick="mQuickWA(\''+t.wa||t.phone+'\',\''+t.name+'\','+t.rent+')">WA</button></div></div>';
  }).join(''):'<div style="text-align:center;padding:16px;color:var(--muted)">All paid up!</div>';

  // Activity
  var acts=dbGet(hk(hid,"activity"));
  document.getElementById("d-activity").innerHTML=acts.length?acts.slice(0,8).map(function(a){return '<div class="act-item"><div class="act-dot"></div><div><div style="font-size:.82rem">'+a.msg+'</div><div style="font-size:.72rem;color:var(--muted)">'+new Date(a.t).toLocaleString("en-PK",{day:"2-digit",month:"short",year:"numeric",hour:"2-digit",minute:"2-digit"})+'</div></div></div>';}).join(''):'<div style="text-align:center;padding:16px;color:var(--muted)">No activity</div>';

  // Maintenance
  document.getElementById("d-maint").innerHTML=issues.length?issues.slice(0,4).map(function(i){return '<div class="oi"><div style="font-weight:600;font-size:.83rem">'+i.title+'</div><span class="badge '+(i.status==="open"?"br":"bo")+'">'+i.status+'</span></div>';}).join(''):'<div style="text-align:center;padding:16px;color:var(--muted)">No open issues</div>';

  // Revenue panel
  var pct2=potRev?Math.round(rev/potRev*100):0;
  document.getElementById("d-rev").innerHTML='<div style="display:flex;justify-content:space-between;margin-bottom:8px"><div><div style="font-size:.68rem;color:var(--muted);text-transform:uppercase">Revenue</div><div style="font-family:var(--mono);font-size:1.2rem;font-weight:600;color:var(--p-green)">Rs. '+mFmt(rev)+'</div></div><div style="text-align:right"><div style="font-size:.68rem;color:var(--muted);text-transform:uppercase">Expenses</div><div style="font-family:var(--mono);font-size:1.2rem;font-weight:600;color:var(--p-red)">Rs. '+mFmt(totalExp2)+'</div></div></div><div class="paid-bar"><div class="paid-fill" style="width:'+pct2+'%"></div></div><div style="font-size:.76rem;color:var(--muted)">'+pct2+'% collected</div>';

  // Health score in dashboard
  document.getElementById("d-health").innerHTML='<div class="health-bar" style="height:12px"><div class="health-fill '+scoreClass+'" style="width:'+score+'%"></div></div><div style="display:flex;justify-content:space-between;margin-top:6px"><span style="font-family:var(--mono);font-size:1.2rem;font-weight:700;color:var(--text)">'+score+'/100</span><span style="font-size:.76rem;color:var(--muted)">'+(score>=70?"Healthy":score>=40?"Needs Attention":"Critical")+'</span></div>';

  // Check-in/out timeline (Feature 8)
  var allTenants=dbGet(hk(hid,"tenants"));
  var timeline=[];
  allTenants.forEach(function(t){
    timeline.push({type:"in",name:t.name,tid:t.tid,date:t.movein});
    if(t.moveout)timeline.push({type:"out",name:t.name,tid:t.tid,date:t.moveout});
  });
  timeline.sort(function(a,b){return b.date.localeCompare(a.date);});
  document.getElementById("d-timeline").innerHTML=timeline.length?'<div class="timeline">'+timeline.slice(0,8).map(function(e){
    return '<div class="tl-item tl-'+e.type+'"><div class="tl-dot"></div><div class="tl-date">'+fdateFull(e.date)+'</div><div style="font-size:.83rem;color:var(--text)">'+(e.type==="in"?"\u2795 ":"\u274C ")+e.name+' <span class="m-tid">'+e.tid+'</span></div></div>';
  }).join('')+'</div>':'<div style="text-align:center;padding:16px;color:var(--muted)">No move-in/out records</div>';

  // Bills
  var allBills=dbGet(hk(hid,"bills")).filter(function(b){return b.status!=="paid";}).sort(function(a,b){return a.due.localeCompare(b.due);}).slice(0,4);
  document.getElementById("d-bills").innerHTML=allBills.length?allBills.map(function(b){return '<div class="oi"><div style="font-weight:600;font-size:.83rem">'+b.name+'</div><div style="font-family:var(--mono);font-size:.81rem">Rs. '+mFmt(b.amount)+'</div></div>';}).join(''):'<div style="text-align:center;padding:12px;color:var(--muted)">No bills due</div>';

  // Renewals
  var renewals=allTenants.filter(function(t){if(t.status!=="active")return false;var months=(new Date()-new Date(t.movein+"T12:00:00"))/2592000000;return months>=11&&months<13;});
  document.getElementById("d-renewals").innerHTML=renewals.length?renewals.map(function(t){return '<div class="oi"><div><div style="font-weight:600">'+t.name+'</div><span class="m-tid">'+t.tid+'</span></div><span class="badge bo">Renew?</span></div>';}).join(''):'<div style="text-align:center;padding:16px;color:var(--muted)">No renewals</div>';
}

// Late fee waiver
function mWaiveLateFee(tid){var hid=currentUser.hid;var w=dbGetO(hk(hid,"late_waived"));w[tid+curM()]=true;dbSetO(hk(hid,"late_waived"),w);mToast("Late fee waived","ok");renderMDash();}
// Quick WhatsApp rent reminder (Feature 13)
function mQuickWA(phone,name,rent){
  var msg="Assalam o Alaikum "+name+"!\nThis is a reminder that your rent of Rs. "+fmt(rent)+" for "+mlabel(curM())+" is due. Please arrange payment at your earliest convenience.\nThank you.";
  window.open("https://wa.me/"+phone.replace(/[^0-9]/g,"")+"?text="+encodeURIComponent(msg),"_blank");
}
// Bulk WA reminders
function mBulkWAReminder(){
  var hid=currentUser.hid;var tenants=dbGet(hk(hid,"tenants")).filter(function(t){return t.status==="active";});
  var paidIds={};dbGet(hk(hid,"pays")).filter(function(p){return p.month===curM()&&p.status==="paid";}).forEach(function(p){paidIds[p.tid]=true;});
  var overdue=tenants.filter(function(t){return !paidIds[t.id];});
  if(!overdue.length){mToast("No overdue tenants","ok");return;}
  overdue.forEach(function(t,i){
    setTimeout(function(){window.open("https://wa.me/"+t.phone.replace(/[^0-9]/g,"")+"?text="+encodeURIComponent("Assalam o Alaikum "+t.name+"!\nRent reminder: Rs. "+fmt(t.rent)+" for "+mlabel(curM())+" is due. Please arrange payment.\nThank you."),"_blank");},i*2000);
  });
  mToast("Opening WhatsApp for "+overdue.length+" tenant(s)","ok");
}

// ÃƒÂ¢Ã¢â‚¬ÂÃ¢â€šÂ¬ÃƒÂ¢Ã¢â‚¬ÂÃ¢â€šÂ¬ÃƒÂ¢Ã¢â‚¬ÂÃ¢â€šÂ¬ TENANTS ÃƒÂ¢Ã¢â‚¬ÂÃ¢â€šÂ¬ÃƒÂ¢Ã¢â‚¬ÂÃ¢â€šÂ¬ÃƒÂ¢Ã¢â‚¬ÂÃ¢â€šÂ¬
function renderMTenants(){
  var hid=currentUser.hid,rooms=dbGet(hk(hid,"rooms")),tenants=dbGet(hk(hid,"tenants"));
  var q=(document.getElementById("mt-q").value||"").toLowerCase(),sf=document.getElementById("mt-sf").value||"";
  var f=tenants.filter(function(t){var ms=!q||t.name.toLowerCase().indexOf(q)>=0||t.phone.indexOf(q)>=0||(t.tid&&t.tid.toLowerCase().indexOf(q)>=0);return ms&&(!sf||t.status===sf);});
  document.getElementById("mt-tbody").innerHTML=f.length?f.map(function(t){var rm=rooms.find(function(r){return r.id===t.room;});
    var rentInc=dbGet(hk(hid,"rent_inc")).find(function(ri){return ri.tid===t.id&&ri.effective<=curM()&&!ri.applied;});
    return "<tr><td><span class=\"m-tid\">"+t.tid+"</span></td><td style=\"font-weight:600\">"+t.name+"</td><td><span class=\"badge bb\">"+(rm?rm.num:"?")+"</span></td><td style=\"font-size:.8rem;color:var(--muted)\">"+t.phone+"</td><td style=\"font-size:.8rem;color:var(--muted)\">"+fdateFull(t.movein)+"</td><td style=\"font-family:var(--mono)\">Rs. "+mFmt(t.rent)+(rentInc?' <span class=\"badge bo\" style=\"font-size:.58rem\">\u2191 Rs. '+mFmt(rentInc.newRent)+' from '+mlabel(rentInc.effective)+'</span>':'')+"</td><td><span class=\"badge "+(t.status==="active"?"bg":"br")+"\">"+(t.status==="active"?"Active":"Out")+"</span></td><td><div style=\"display:flex;gap:4px;flex-wrap:wrap\"><button class=\"btn btn-out btn-sm\" onclick=\"mViewTen('"+t.id+"')\">View</button><button class=\"btn btn-blue btn-sm\" onclick=\"mShowCreds('"+t.id+"')\">Login</button>"+(t.status==="active"?"<button class=\"btn btn-out btn-sm\" onclick=\"mTransferRoom('"+t.id+"')\">Transfer</button><button class=\"btn btn-out btn-sm\" onclick=\"mRentIncrease('"+t.id+"')\">Rent \u2191</button><button class=\"btn btn-out btn-sm\" onclick=\"mOpenSettlement('"+t.id+"')\">Settle</button><button class=\"btn btn-red btn-sm\" onclick=\"mCheckout('"+t.id+"')\">Out</button>":"")+"</div></td></tr>";
  }).join(''):"<tr><td colspan=\"8\" style=\"text-align:center;padding:40px;color:var(--muted)\">No tenants</td></tr>";
}

// View tenant with comm log + docs + room condition
function mViewTen(id){
  var hid=currentUser.hid,t=dbGet(hk(hid,"tenants")).find(function(x){return x.id===id;});if(!t)return;
  var rm=dbGet(hk(hid,"rooms")).find(function(r){return r.id===t.room;});
  var tpay=dbGet(hk(hid,"pays")).filter(function(p){return p.tid===id;});var total=tpay.reduce(function(s,p){return s+p.amount;},0);
  var accs=dbGetO(hk(hid,"taccs"));var creds=Object.values(accs).find(function(a){return a.tid===id;});
  var comms=dbGet(hk(hid,"comms")).filter(function(c){return c.tid===id;}).sort(function(a,b){return b.date.localeCompare(a.date);});
  document.getElementById("mvt-title").textContent=t.name+" \u2014 "+t.tid;
  var commHtml=comms.length?comms.map(function(c){return '<div style="padding:6px 0;border-bottom:1px solid var(--bd);font-size:.82rem"><div style="color:var(--text)">'+c.note+'</div><div style="font-size:.68rem;color:var(--muted)">'+fdateFull(c.date)+' \u00B7 By: '+(c.by||"Manager")+'</div></div>';}).join(''):'<div style="color:var(--muted);font-size:.8rem">No notes yet</div>';
  document.getElementById("m-view-content").innerHTML=""
    +'<div class="mvt-g">'+mFld("Tenant ID",t.tid)+mFld("Name",t.name)+mFld("Father",t.father)+mFld("Phone",t.phone+'<br><a href="https://wa.me/'+t.phone.replace(/[^0-9]/g,"")+'" target="_blank" style="color:var(--p-green);font-size:.72rem">\uD83D\uDCAC WhatsApp</a>')+mFld("Emergency",t.emergency)+mFld("CNIC",t.cnic)+mFld("Room",rm?rm.num:"\u2014")+mFld("Occupation",t.occupation)+mFld("Employer",t.employer)+mFld("Move-In",fdateFull(t.movein))+mFld("Rent","Rs. "+mFmt(t.rent))+mFld("Deposit","Rs. "+mFmt(t.deposit||0))+'</div>'
    +(t.notes?'<div class="m-notes">'+t.notes+'</div>':'')
    +(creds?'<div class="mcred">Username: <code>'+creds.uid+'</code> Password: <code>'+creds.pass+'</code></div>':'')
    +'<div class="mvt-sec">Communication Log (Feature 12) <button class="btn btn-blue btn-sm" style="float:right" onclick="mAddComm(\''+id+'\')">+ Add Note</button></div>'
    +'<div style="max-height:160px;overflow-y:auto">'+commHtml+'</div>'
    +'<div class="mvt-sec">Payments ('+tpay.length+' records, Total Rs. '+mFmt(total)+')</div>'
    +'<div style="max-height:140px;overflow-y:auto;border:1px solid var(--bd);border-radius:7px">'+(tpay.length?tpay.sort(function(a,b){return b.date.localeCompare(a.date);}).slice(0,10).map(function(p){return '<div style="display:flex;justify-content:space-between;padding:6px 12px;border-bottom:1px solid var(--bd);font-size:.82rem"><span>'+mlabel(p.month)+'</span><span style="color:var(--p-green)">Rs. '+mFmt(p.amount)+'</span><span style="color:var(--muted)">'+fdate(p.date)+'</span></div>';}).join(''):'<div style="text-align:center;padding:20px;color:var(--muted)">No payments</div>')+'</div>';
  openMM("view-ten");
}
