function renderMAttendance(){
  var hid=currentUser.hid;var tenants=dbGet(hk(hid,"tenants")).filter(function(t){return t.status==="active";});
  var staff=dbGet(hk(hid,"staff"));
  var todayKey="att_"+today().replace(/-/g,"");
  var att=dbGetO(hk(hid,todayKey));
  var staffAttKey="staff_att_"+today().replace(/-/g,"");
  var staffAtt=dbGetO(hk(hid,staffAttKey));
  document.getElementById("ma-date").textContent=fdateFull(today());
  var tPresent=Object.values(att).filter(function(v){return v;}).length;
  var sPresent=Object.keys(staffAtt).length;
  document.getElementById("ma-count").textContent="Tenants: "+tPresent+"/"+tenants.length+" \u00B7 Staff: "+sPresent+"/"+staff.length;
  var staffHtml=staff.length?'<div style="font-weight:600;font-size:.82rem;color:var(--gold);margin:16px 0 8px;padding-bottom:6px;border-bottom:1px solid var(--bd)">Staff Attendance</div><div class="att-grid">'+staff.map(function(s){
    var isIn=staffAtt[s.name]?true:false;
    var inTime=staffAtt[s.name]&&staffAtt[s.name].in?new Date(staffAtt[s.name].in).toLocaleTimeString("en-PK",{hour:"2-digit",minute:"2-digit"}):"";
    var outTime=staffAtt[s.name]&&staffAtt[s.name].out?new Date(staffAtt[s.name].out).toLocaleTimeString("en-PK",{hour:"2-digit",minute:"2-digit"}):"";
    return '<div class="att-cell '+(isIn?"present":"absent")+'"><div style="font-weight:600;font-size:.82rem">'+s.name.split(" ")[0]+'</div><div style="font-size:.65rem;color:var(--muted)">'+s.role+'</div><div style="font-size:.9rem;margin-top:4px">'+(isIn?"\u2705":"\u274C")+'</div>'+(inTime?'<div style="font-size:.62rem;color:var(--muted);margin-top:2px">In: '+inTime+(outTime?" \u00B7 Out: "+outTime:"")+'</div>':'')+'</div>';
  }).join('')+'</div>':'';
  document.getElementById("ma-grid").innerHTML='<div style="font-weight:600;font-size:.82rem;color:var(--gold);margin-bottom:8px;padding-bottom:6px;border-bottom:1px solid var(--bd)">Tenant Attendance</div><div class="att-grid">'+tenants.map(function(t){
    var isPresent=att[t.id]||false;
    return '<div class="att-cell '+(isPresent?"present":"absent")+'" onclick="mToggleAtt(\''+t.id+'\')"><div style="font-weight:600;font-size:.82rem">'+t.name.split(" ")[0]+'</div><div style="font-size:.68rem;margin-top:2px"><span class="m-tid">'+t.tid+'</span></div><div style="font-size:.9rem;margin-top:4px">'+(isPresent?"\u2705":"\u274C")+'</div></div>';
  }).join('')+'</div>'+staffHtml;
}
function mToggleAtt(tid){
  var hid=currentUser.hid;var todayKey="att_"+today().replace(/-/g,"");
  var att=dbGetO(hk(hid,todayKey));att[tid]=!att[tid];dbSetO(hk(hid,todayKey),att);renderMAttendance();
}

// ÃƒÂ¢Ã¢â‚¬ÂÃ¢â€šÂ¬ÃƒÂ¢Ã¢â‚¬ÂÃ¢â€šÂ¬ÃƒÂ¢Ã¢â‚¬ÂÃ¢â€šÂ¬ SETTINGS ÃƒÂ¢Ã¢â‚¬ÂÃ¢â€šÂ¬ÃƒÂ¢Ã¢â‚¬ÂÃ¢â€šÂ¬ÃƒÂ¢Ã¢â‚¬ÂÃ¢â€šÂ¬
function renderMSettings(){
  var hid=currentUser.hid;var h=HOSTELS.find(function(x){return x&&x.id===hid;});
  document.getElementById("set-info").innerHTML=mFld("Hostel",h?h.name:"\u2014")+mFld("Manager",currentUser.name)+mFld("Username",'<code style="color:#E8A84B">'+currentUser.user+'</code>');
  mPopTenSel("set-ten-sel");
  // Late fee config (Feature 19)
  var cfg=dbGetO(hk(hid,"config"));
  var lateFeeEl=document.getElementById("set-latefee");if(lateFeeEl)lateFeeEl.value=cfg.lateFee||"";
  var lateDayEl=document.getElementById("set-lateday");if(lateDayEl)lateDayEl.value=cfg.lateDay||10;
  // Meal menu config (Feature 23)
  var menuEl=document.getElementById("set-menu");if(menuEl)menuEl.value=cfg.mealMenu||"";
}
function mChangePwd(){var cur=document.getElementById("set-cpwd").value,nw=document.getElementById("set-npwd").value,conf=document.getElementById("set-cnfpwd").value;var acc=MGRS.find(function(a){return a.user===currentUser.user;});if(!acc||acc.pass!==cur){mToast("Wrong password","err");return;}if(!nw||nw.length<4){mToast("Too short","err");return;}if(nw!==conf){mToast("Mismatch","err");return;}acc.pass=nw;currentUser.pass=nw;["set-cpwd","set-npwd","set-cnfpwd"].forEach(function(id){document.getElementById(id).value="";});mToast("Updated","ok");}
function mResetTenPwd(){var hid=currentUser.hid,tid=(document.getElementById("set-ten-sel")||{}).value;if(!tid){mToast("Select tenant","err");return;}var accs=dbGetO(hk(hid,"taccs")),creds=Object.values(accs).find(function(a){return a.tid===tid;});if(!creds){mToast("No account","err");return;}var np="lbh"+String(Math.floor(1000+Math.random()*9000));creds.pass=np;dbSetO(hk(hid,"taccs"),accs);document.getElementById("set-ten-result").innerHTML='<div class="hint-box">New: <code style="color:#3DD68C">'+np+'</code></div>';mToast("Reset","ok");}
function mSaveLateFee(){var hid=currentUser.hid;var cfg=dbGetO(hk(hid,"config"));cfg.lateFee=parseInt(document.getElementById("set-latefee").value)||0;cfg.lateDay=parseInt(document.getElementById("set-lateday").value)||10;dbSetO(hk(hid,"config"),cfg);mToast("Late fee saved","ok");}
function mSaveMenu(){var hid=currentUser.hid;var cfg=dbGetO(hk(hid,"config"));cfg.mealMenu=document.getElementById("set-menu").value;dbSetO(hk(hid,"config"),cfg);mToast("Menu saved","ok");}

// ÃƒÂ¢Ã¢â‚¬ÂÃ¢â€šÂ¬ÃƒÂ¢Ã¢â‚¬ÂÃ¢â€šÂ¬ÃƒÂ¢Ã¢â‚¬ÂÃ¢â€šÂ¬ MODAL + TENANT HELPERS ÃƒÂ¢Ã¢â‚¬ÂÃ¢â€šÂ¬ÃƒÂ¢Ã¢â‚¬ÂÃ¢â€šÂ¬ÃƒÂ¢Ã¢â‚¬ÂÃ¢â€šÂ¬
function openMM(n){if(n==="add-maint")mPopStaffSel();if(n==="add-expense"){mPopExpMaintSel();document.getElementById("exp-date").value=today();}if(n==="add-bill")document.getElementById("bill-due").value=today();if(n==="add-staff")document.getElementById("sf-start").value=today();if(n==="add-visitor")mPopTenSel("vis-tenant");var el=document.getElementById("mm-"+n);if(el)el.classList.add("open");}
function closeMM(n){var el=document.getElementById("mm-"+n);if(el)el.classList.remove("open");}
function mPopRoomSel(selId){var hid=currentUser.hid,rooms=dbGet(hk(hid,"rooms")),tenants=dbGet(hk(hid,"tenants")).filter(function(t){return t.status==="active";});var sel=document.getElementById(selId);if(!sel)return;sel.innerHTML='<option value="">Select room</option>';rooms.forEach(function(r){var occ=tenants.filter(function(t){return t.room===r.id;}).length;var free=r.cap-occ;if(free>0)sel.innerHTML+='<option value="'+r.id+'">'+r.num+' ('+r.cap+'-person, '+free+' free)</option>';});}
function mSaveTen(){
  var hid=currentUser.hid,name=document.getElementById("mtn").value.trim(),phone=document.getElementById("mtp").value.trim(),room=document.getElementById("mtr").value,movein=document.getElementById("mtmi").value;
  if(!name||!phone||!room||!movein){mToast("Fill required","err");return;}
  var tid=nextTid(hid);
  var t={id:dbId(),tid:tid,name:name,phone:phone,father:document.getElementById("mtf").value.trim(),emergency:document.getElementById("mte").value.trim(),cnic:document.getElementById("mtc").value.trim(),occupation:(document.getElementById("mto")||{}).value||"",employer:document.getElementById("mtins").value.trim(),room:room,movein:movein,rent:parseInt(document.getElementById("mtrnt").value)||6500,deposit:parseInt(document.getElementById("mtdep").value)||0,otype:(document.getElementById("mtoty")||{}).value||"sharing",notes:document.getElementById("mtnts").value.trim(),status:"active",addedOn:new Date().toISOString()};
  var arr=dbGet(hk(hid,"tenants"));arr.push(t);dbSet(hk(hid,"tenants"),arr);
  var uname=tid.toLowerCase().replace("-",".");var pwd="lbh"+String(Math.floor(1000+Math.random()*9000));
  var accs=dbGetO(hk(hid,"taccs"));accs[uname]={pass:pwd,tid:t.id,name:name,uid:uname};dbSetO(hk(hid,"taccs"),accs);
  mLog("Tenant added: "+name+" ("+tid+")");closeMM("add-ten");
  ["mtn","mtf","mtp","mte","mtc","mtins","mtnts","mtdep"].forEach(function(id){var el=document.getElementById(id);if(el)el.value="";});
  document.getElementById("m-cred-info").innerHTML='<div class="mcred">Tenant: <strong style="color:var(--text)">'+name+'</strong><br>ID: <code>'+tid+'</code><br>Username: <code>'+uname+'</code><br>Password: <code>'+pwd+'</code></div>';
  openMM("show-creds");mToast(tid+" added");renderMTenants();
}
function mShowCreds(id){var hid=currentUser.hid,accs=dbGetO(hk(hid,"taccs")),creds=Object.values(accs).find(function(a){return a.tid===id;});var t=dbGet(hk(hid,"tenants")).find(function(x){return x.id===id;});document.getElementById("m-cred-info").innerHTML=creds?'<div class="mcred">'+(t?'<strong style="color:var(--text)">'+t.name+'</strong> <span class="m-tid">'+t.tid+'</span><br>':'')+'Username: <code>'+creds.uid+'</code><br>Password: <code>'+creds.pass+'</code></div>':'<div class="warn-box">No account</div>';openMM("show-creds");}
function mCheckout(id){if(!confirm("Move out?"))return;var hid=currentUser.hid,arr=dbGet(hk(hid,"tenants")),t=arr.find(function(x){return x.id===id;});t.status="inactive";t.moveout=today();dbSet(hk(hid,"tenants"),arr);mLog(t.name+" moved out");mToast(t.name+" moved out");renderMTenants();}
// Monthly report (Feature 17)
function mGenReport(){
  var hid=currentUser.hid;var h=HOSTELS.find(function(x){return x&&x.id===hid;});
  var tenants=dbGet(hk(hid,"tenants"));var active=tenants.filter(function(t){return t.status==="active";});
  var rooms=dbGet(hk(hid,"rooms"));var totalBeds=rooms.reduce(function(s,r){return s+r.cap;},0);
  var pays=dbGet(hk(hid,"pays")).filter(function(p){return p.month===curM();});
  var rev=pays.filter(function(p){return p.status==="paid";}).reduce(function(s,p){return s+p.amount;},0);
  var potRev=active.reduce(function(s,t){return s+t.rent;},0);
  var expenses=dbGet(hk(hid,"expenses")).filter(function(e){return (e.date||"").substring(0,7)===curM();});
  var totalExp=expenses.reduce(function(s,e){return s+e.amount;},0);
  var issues=dbGet(hk(hid,"maint")).filter(function(i){return i.status!=="resolved";});
  var movedIn=tenants.filter(function(t){return t.movein&&t.movein.substring(0,7)===curM();}).length;
  var movedOut=tenants.filter(function(t){return t.moveout&&t.moveout.substring(0,7)===curM();}).length;
  var w=window.open("","_blank","width=600,height=800");
  w.document.write('<!DOCTYPE html><html><head><title>Monthly Report</title><style>body{font-family:Georgia,serif;padding:2rem;max-width:540px;margin:auto;color:#1a1a2e}.row{display:flex;justify-content:space-between;padding:.45rem 0;border-bottom:1px solid #eee;font-size:.9rem}h3{margin-top:1.2rem;color:#333;border-bottom:2px solid #1a1a2e;padding-bottom:4px}@media print{button{display:none}}</style></head><body><h2>Monthly Report \u2014 '+mlabel(curM())+'</h2><p style="color:#666">'+(h?h.name:"LahoreBoysHostels")+'</p><hr/><h3>Occupancy</h3><div class="row"><span>Active Tenants</span><span>'+active.length+'/'+totalBeds+'</span></div><div class="row"><span>Occupancy Rate</span><span>'+Math.round(active.length/(totalBeds||1)*100)+'%</span></div><div class="row"><span>New Move-Ins</span><span>'+movedIn+'</span></div><div class="row"><span>Move-Outs</span><span>'+movedOut+'</span></div><h3>Financials</h3><div class="row"><span>Expected Revenue</span><span>Rs. '+fmt(potRev)+'</span></div><div class="row"><span>Collected</span><span style="color:#2e7d32">Rs. '+fmt(rev)+'</span></div><div class="row"><span>Collection Rate</span><span>'+Math.round(rev/(potRev||1)*100)+'%</span></div><div class="row"><span>Expenses</span><span style="color:#c62828">Rs. '+fmt(totalExp)+'</span></div><div class="row" style="font-weight:700;border-top:2px solid #1a1a2e"><span>Net Profit</span><span>'+(rev-totalExp>=0?"+":"")+'Rs. '+fmt(rev-totalExp)+'</span></div><h3>Maintenance</h3><div class="row"><span>Open Issues</span><span>'+issues.length+'</span></div><p style="margin-top:2rem;font-size:.75rem;color:#999;text-align:center">Generated '+new Date().toLocaleString("en-PK")+'</p><br><button onclick="window.print()" style="padding:.5rem 1.2rem;background:#1a1a2e;color:white;border:none;border-radius:5px;cursor:pointer">Print</button></body></html>');
  w.document.close();
}

// ÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚Â
// HOSTELITE PORTAL ÃƒÂ¢Ã¢â€šÂ¬Ã¢â‚¬Â Full Feature Set
// ÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚Â
function renderHtDash(){
  if(!currentUser||currentUser.role!=="hostelite")return;
  var hid=currentUser.hid,tid=currentUser.tid;
  var tenants=dbGet(hk(hid,"tenants")),t=tenants.find(function(x){return x.id===tid;});
  var h=HOSTELS.find(function(x){return x&&x.id===hid;});
  if(!t){document.getElementById("ht-welcome").textContent="Account Error";return;}
  var rooms=dbGet(hk(hid,"rooms")),rm=rooms.find(function(r){return r.id===t.room;});
  var roommates=tenants.filter(function(x){return x.room===t.room&&x.id!==tid&&x.status==="active";});
  var pays=dbGet(hk(hid,"pays")).filter(function(p){return p.tid===tid;}).sort(function(a,b){return b.month.localeCompare(a.month);});
  var totalPaid=pays.reduce(function(s,p){return s+p.amount;},0);
  var curPay=pays.filter(function(p){return p.month===curM();});
  var paid=curPay.reduce(function(s,p){return s+p.amount;},0);var balance=paid-t.rent;
  var notices=dbGet(hk(hid,"notices")).sort(function(a,b){return (b.pinned||0)-(a.pinned||0);});
  var complaints=dbGet(hk(hid,"maint")).filter(function(i){return i.tenTid===t.tid;});
  var cfg=dbGetO(hk(hid,"config"));

  document.getElementById("ht-hname").textContent=h?h.name:"";
  document.getElementById("ht-tid-nav").textContent=t.tid;
  document.getElementById("ht-welcome").textContent="Welcome back, "+currentUser.name.split(" ")[0]+"!";
  document.getElementById("ht-sub").textContent=(h?h.name+" \u00B7 ":"")+t.tid+" \u00B7 "+(rm?rm.num:"\u2014");
  document.getElementById("ht-room-stat").textContent=rm?rm.num:"\u2014";
  document.getElementById("ht-rent-stat").textContent="Rs. "+mFmt(t.rent);
  document.getElementById("ht-paid-stat").textContent="Rs. "+mFmt(paid);
  document.getElementById("ht-bal-stat").textContent=(balance>=0?"+":"\u2212")+"Rs. "+mFmt(Math.abs(balance));
  document.getElementById("ht-bal-stat").style.color=balance>=0?"#3DD68C":"#FF5C5C";
  document.getElementById("ht-bal-lbl").textContent=balance>0?"In credit":balance<0?"Outstanding":"Settled";

  // Payment due card (Feature 20)
  var daysLeft=new Date(new Date().getFullYear(),new Date().getMonth()+1,0).getDate()-new Date().getDate();
  var payStatus=paid>=t.rent?"paid":paid>0?"partial":"unpaid";
  document.getElementById("ht-due-card").innerHTML='<div style="display:flex;justify-content:space-between;align-items:center;padding:12px 16px;background:'+(payStatus==="paid"?"rgba(61,214,140,.08)":payStatus==="partial"?"rgba(255,154,60,.08)":"rgba(255,92,92,.08)")+';border:1px solid '+(payStatus==="paid"?"rgba(61,214,140,.25)":"rgba(255,92,92,.25)")+';border-radius:10px"><div><div style="font-weight:700;font-size:.95rem;color:var(--text)">'+(payStatus==="paid"?"\u2705 Rent Paid for "+mlabel(curM()):payStatus==="partial"?"\u26A0 Partial: Rs. "+mFmt(paid)+" of Rs. "+mFmt(t.rent):"\u274C Rent Due: Rs. "+mFmt(t.rent))+'</div><div style="font-size:.76rem;color:var(--muted);margin-top:3px">'+daysLeft+' days left in '+mlabel(curM())+'</div></div>'+(payStatus!=="paid"?'<button class="btn btn-gold btn-sm" onclick="htPayCommit()">Promise to Pay</button>':'')+'</div>';

  // Profile
  document.getElementById("ht-profile").innerHTML='<div class="ht-pr"><span style="color:#6B7A99">Tenant ID</span><span class="m-tid">'+t.tid+'</span></div><div class="ht-pr"><span style="color:#6B7A99">Room</span><span style="font-weight:600">'+(rm?rm.num:"\u2014")+'</span></div><div class="ht-pr"><span style="color:#6B7A99">Move-In</span><span>'+fdateFull(t.movein)+'</span></div><div class="ht-pr"><span style="color:#6B7A99">Total Paid</span><span style="color:#3DD68C;font-weight:600">Rs. '+mFmt(totalPaid)+'</span></div>';

  // Notices preview
  document.getElementById("ht-notices-prev").innerHTML=notices.length?notices.slice(0,3).map(function(n){return '<div style="padding:5px 0;border-bottom:1px solid rgba(42,51,71,.4);font-size:.78rem"><div style="color:var(--text);font-weight:500">'+(n.pinned?"\uD83D\uDCCC ":"")+n.title+'</div><div style="font-size:.68rem;color:#6B7A99">'+fdate(n.date)+'</div></div>';}).join(''):'<div style="text-align:center;padding:16px;color:#6B7A99">No notices</div>';

  // Payments tab
  document.getElementById("ht-pay-total").textContent="Total: Rs. "+mFmt(totalPaid);
  document.getElementById("ht-pay-hist").innerHTML=pays.length?pays.map(function(p){return '<div class="ht-pr"><span style="font-size:.77rem;color:#6B7A99">'+mlabel(p.month)+'</span><span class="badge '+(PBDGS[p.ptype||"regular"]||"bgold")+'">'+PLBLS[p.ptype||"regular"]+'</span><span style="color:#3DD68C;font-weight:600">Rs. '+mFmt(p.amount)+'</span><span style="color:#6B7A99;font-size:.73rem">'+fdate(p.date)+'</span><button class="mb mb-out mb-sm" onclick="printReceipt(\''+p.id+'\',\''+tid+'\','+hid+')">Receipt</button></div>';}).join(''):'<div style="text-align:center;padding:20px;color:#6B7A99">No payments</div>';

  // Room tab
  document.getElementById("ht-room-detail").innerHTML='<div class="ht-pr"><span style="color:#6B7A99">Room</span><span class="badge bb">'+(rm?rm.num:"\u2014")+'</span></div><div class="ht-pr"><span style="color:#6B7A99">Type</span><span>'+(rm?rm.cap+"-person":"\u2014")+'</span></div><div class="ht-pr"><span style="color:#6B7A99">Rent</span><span style="font-weight:600">Rs. '+mFmt(t.rent)+'</span></div>';
  document.getElementById("ht-roommates").innerHTML=roommates.length?roommates.map(function(r){return '<div class="ht-rm">\uD83D\uDC64 <span style="font-weight:600">'+r.name+'</span></div>';}).join(''):'<div style="text-align:center;padding:12px;color:#6B7A99">No roommates</div>';

  // Notices full
  document.getElementById("ht-notices-full").innerHTML=notices.length?notices.map(function(n){return '<div class="ncard"><div style="font-weight:600">'+(n.pinned?"\uD83D\uDCCC ":"")+n.title+'</div><span class="badge bo" style="font-size:.63rem">'+n.cat+'</span><div style="font-size:.8rem;color:#9AAAB8;margin-top:7px">'+n.body+'</div><div style="font-size:.67rem;color:#6B7A99;margin-top:5px">'+fdate(n.date)+'</div></div>';}).join(''):'<div style="text-align:center;padding:40px;color:#6B7A99">No notices</div>';

  // My complaints (Feature 22)
  document.getElementById("ht-my-complaints").innerHTML=complaints.length?complaints.map(function(c){return '<div class="mcard"><div class="mcard-hdr"><div><div style="font-weight:600;font-size:.88rem">'+c.title+'</div><div style="font-size:.73rem;color:var(--muted)">'+c.cat+' \u00B7 '+fdate(c.addedOn)+'</div></div><span class="badge '+(c.status==="open"?"br":c.status==="resolved"?"bg":"bo")+'">'+c.status+'</span></div>'+(c.desc?'<div style="font-size:.82rem;color:var(--muted);margin-top:4px">'+c.desc+'</div>':'')+(c.resolvedOn?'<div style="font-size:.72rem;color:var(--p-green);margin-top:4px">Resolved: '+fdate(c.resolvedOn)+'</div>':'')+'</div>';}).join(''):'<div style="text-align:center;padding:30px;color:var(--muted)">No complaints submitted</div>';

  // Documents on file (Feature 26)
  var tdocs=(dbGetO(hk(hid,"docs"))[tid])||[];
  document.getElementById("ht-my-docs").innerHTML=tdocs.length?tdocs.map(function(d){return '<div class="mdoc-chip" style="margin:3px">'+d.name+'</div>';}).join(''):'<div style="color:var(--muted);font-size:.82rem">No documents on file yet.</div>';

  // Emergency contacts (Feature 27)
  document.getElementById("ht-emergency").innerHTML='<div class="ht-pr"><span style="color:#6B7A99">Hostel Manager</span><span style="font-weight:600">'+(h?h.owner:"\u2014")+' <a href="tel:'+(h?h.phone.replace(/\s/g,""):"")+'\'" style="color:var(--p-blue);font-size:.78rem;margin-left:6px">\uD83D\uDCDE Call</a>'+(h?' <a href="https://wa.me/'+h.wa+'" target="_blank" style="color:var(--p-green);font-size:.78rem;margin-left:4px">\uD83D\uDCAC WA</a>':'')+'</span></div>'+(h&&h.owner2?'<div class="ht-pr"><span style="color:#6B7A99">Assistant</span><span>'+h.owner2+' <a href="tel:'+(h.phone2||"").replace(/\s/g,"")+'" style="color:var(--p-blue);font-size:.78rem;margin-left:6px">\uD83D\uDCDE</a></span></div>':'');

  // Meal menu (Feature 23)
  if(h&&h.meals&&cfg.mealMenu){
    document.getElementById("ht-meal-menu").innerHTML='<div style="background:var(--sf);border:1px solid var(--bd);border-radius:10px;padding:14px 16px"><div style="font-weight:600;color:var(--gold);margin-bottom:8px">\uD83C\uDF7D Meal Schedule</div><div style="font-size:.83rem;color:var(--text);line-height:1.7;white-space:pre-wrap">'+cfg.mealMenu+'</div></div>';
  } else {
    document.getElementById("ht-meal-menu").innerHTML='';
  }
}
function htSwitchTab(tab){document.querySelectorAll(".httab").forEach(function(b){b.classList.toggle("active",b.dataset.tab===tab);});document.querySelectorAll(".ht-panel").forEach(function(p){p.style.display=p.dataset.panel===tab?"block":"none";});}
// Payment commitment (Feature 21)
function htPayCommit(){
  var date=prompt("When will you pay? (YYYY-MM-DD):");if(!date)return;
  var hid=currentUser.hid;var commits=dbGet(hk(hid,"pay_commits"));
  commits.push({tid:currentUser.tid,name:currentUser.name,date:date,month:curM(),createdOn:new Date().toISOString()});
  dbSet(hk(hid,"pay_commits"),commits);
  addNotif(currentUser.name+" promised to pay by "+fdate(date),"manager");
  mToast("Commitment recorded. Manager notified.","ok");
  renderHtDash();
}
// Complaint with auto reporter (Feature 22 + Fix)
function htSubmitComplaint(){
  var hid=currentUser.hid,tid=currentUser.tid;var ten=dbGet(hk(hid,"tenants")).find(function(x){return x.id===tid;});
  var title=document.getElementById("ht-comp-title").value.trim(),desc=document.getElementById("ht-comp-desc").value.trim();
  var res=document.getElementById("ht-comp-result");
  if(!title||!desc){res.innerHTML='<div class="warn-box">Fill title and description.</div>';return;}
  var arr=dbGet(hk(hid,"maint"));
  arr.unshift({id:dbId(),title:title,cat:document.getElementById("ht-comp-cat").value,room:ten?ten.room:"",desc:desc,reporter:currentUser.name,tenTid:ten?ten.tid:"",pri:document.getElementById("ht-comp-pri").value,status:"open",addedOn:new Date().toISOString()});
  dbSet(hk(hid,"maint"),arr);
  addNotif("Complaint from "+currentUser.name+": "+title,"manager");
  document.getElementById("ht-comp-title").value="";document.getElementById("ht-comp-desc").value="";
  res.innerHTML='<div class="hint-box">Submitted by '+currentUser.name+'. Management notified.</div>';
  setTimeout(function(){res.innerHTML="";renderHtDash();},3000);
}
// Move-out request with 5-day notice (Feature 24)
function htRequestMoveOut(){
  openMM("ht-moveout-req");
}
function htDoMoveOut(){
  var date=document.getElementById("ht-mo-date").value;
  if(!date){mToast("Select a date","err");return;}
  var minDate=new Date();minDate.setDate(minDate.getDate()+5);
  var reqDate=new Date(date+"T12:00:00");
  if(reqDate<minDate){mToast("Minimum 5-day notice required. Earliest: "+minDate.toISOString().substring(0,10),"err");return;}
  var hid=currentUser.hid;var reqs=dbGet(hk(hid,"moveout_reqs"));
  reqs.push({tid:currentUser.tid,name:currentUser.name,requestedDate:date,submittedOn:today(),status:"pending"});
  dbSet(hk(hid,"moveout_reqs"),reqs);
  addNotif(currentUser.name+" requested move-out on "+fdate(date),"manager");
  closeMM("ht-moveout-req");mToast("Move-out request submitted for "+fdate(date),"ok");
}
// Room swap request (Feature 28)
function htRequestRoomSwap(){
  openMM("ht-swap-req");
}
function htDoSwap(){
  var reason=document.getElementById("ht-swap-reason").value.trim();
  if(!reason){mToast("Enter a reason","err");return;}
  var hid=currentUser.hid;var reqs=dbGet(hk(hid,"room_swap_reqs"));
  reqs.push({tid:currentUser.tid,name:currentUser.name,reason:reason,submittedOn:today(),status:"pending"});
  dbSet(hk(hid,"room_swap_reqs"),reqs);
  addNotif(currentUser.name+" requested room swap","manager");
  closeMM("ht-swap-req");mToast("Room swap request submitted","ok");
}
// Guest registration (Feature 29)
function htRequestGuest(){
  openMM("ht-guest-req");
}
function htDoGuestReq(){
  var guestName=document.getElementById("ht-guest-name").value.trim();
  var guestDate=document.getElementById("ht-guest-date").value;
  if(!guestName||!guestDate){mToast("Fill all fields","err");return;}
  var hid=currentUser.hid;var reqs=dbGet(hk(hid,"guest_reqs"));
  reqs.push({tid:currentUser.tid,name:currentUser.name,guestName:guestName,date:guestDate,submittedOn:today(),status:"pending",note:"Physical meeting with manager required. Payment may apply."});
  dbSet(hk(hid,"guest_reqs"),reqs);
  addNotif(currentUser.name+" requested guest visit: "+guestName+" on "+fdate(guestDate),"manager");
  closeMM("ht-guest-req");mToast("Guest request submitted. Physical meeting with manager required.","ok");
}
// Feedback (Feature 30)
function htSubmitFeedback(){
  var clean=parseInt(document.getElementById("ht-fb-clean").value)||0;
  var food=parseInt(document.getElementById("ht-fb-food").value)||0;
  var mgmt=parseInt(document.getElementById("ht-fb-mgmt").value)||0;
  if(!clean||!mgmt){mToast("Rate at least cleanliness and management","err");return;}
  var hid=currentUser.hid;var fb=dbGet(hk(hid,"feedback"));
  fb.push({id:dbId(),month:curM(),cleanliness:clean,food:food,management:mgmt,submittedOn:new Date().toISOString()});
  dbSet(hk(hid,"feedback"),fb);
  mToast("Feedback submitted anonymously. Thank you!","ok");
  document.getElementById("ht-fb-result").innerHTML='<div class="hint-box">Thank you for your feedback!</div>';
}
// Receipt printer
function printReceipt(payId,tid,hid){
  var p=dbGet(hk(hid,"pays")).find(function(x){return x.id===payId;});
  var ten=dbGet(hk(hid,"tenants")).find(function(x){return x.id===tid;});
  var h=HOSTELS.find(function(x){return x&&x.id===hid;});if(!p||!ten)return;
  var rm=dbGet(hk(hid,"rooms")).find(function(r){return r.id===ten.room;});
  var w=window.open("","_blank","width=520,height=720");
  w.document.write('<!DOCTYPE html><html><head><title>Receipt</title><style>body{font-family:Georgia,serif;padding:2.5rem;max-width:460px;margin:auto}.row{display:flex;justify-content:space-between;padding:.42rem 0;border-bottom:1px solid #eee;font-size:.88rem}.total{display:flex;justify-content:space-between;font-weight:700;font-size:.98rem;border-top:2px solid #1a1a2e;padding:.55rem 0;margin-top:.4rem}@media print{button{display:none}}</style></head><body><h2>Rent Receipt</h2><p style="color:#666">'+(h?h.name:'LBH')+'</p><hr/><div class="row"><span>Tenant</span><span>'+ten.name+'</span></div><div class="row"><span>ID</span><span>'+ten.tid+'</span></div><div class="row"><span>Room</span><span>'+(rm?rm.num:"\u2014")+'</span></div><div class="row"><span>Period</span><span>'+mlabel(p.month)+'</span></div><div class="row"><span>Paid</span><span>'+fdate(p.date)+'</span></div><div class="row"><span>Method</span><span>'+p.method+'</span></div><div class="total"><span>Amount</span><span>Rs. '+mFmt(p.amount)+'</span></div><p style="margin-top:2rem;font-size:.72rem;color:#999;text-align:center">LahoreBoysHostels \u00B7 '+new Date().toLocaleDateString("en-PK")+'</p><br><button onclick="window.print()" style="padding:.5rem 1.2rem;background:#1a1a2e;color:white;border:none;border-radius:5px;cursor:pointer">Print</button></body></html>');
  w.document.close();
}

// ÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚Â
// STAFF PORTAL
// ÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚Â
function renderStaffPortal(){
  if(!currentUser||currentUser.role!=="staff")return;
  var hid=currentUser.hid,h=HOSTELS.find(function(x){return x&&x.id===hid;});
  document.getElementById("sp-hname").textContent=h?h.name:"Staff Portal";
  document.getElementById("sp-uname").textContent=currentUser.name+" ("+currentUser.staffRole+")";
  var issues=dbGet(hk(hid,"maint"));var myIssues=issues.filter(function(i){return i.assigned===currentUser.name;});
  var notices=dbGet(hk(hid,"notices")).sort(function(a,b){return (b.pinned||0)-(a.pinned||0);});
  var dailyTasks=dbGet(hk(hid,"daily_tasks")).filter(function(t){return t.date===today();});
  // Staff attendance (Feature 31)
  var todayKey="staff_att_"+today().replace(/-/g,"");
  var staffAtt=dbGetO(hk(hid,todayKey));
  var amCheckedIn=staffAtt[currentUser.staffId||currentUser.name]||false;

  document.getElementById("sp-stats").innerHTML=""
    +'<div class="stat-card" style="--accent:var(--p-blue)"><div class="slabel">My Tasks</div><div class="sval">'+myIssues.filter(function(i){return i.status!=="resolved";}).length+'</div></div>'
    +'<div class="stat-card" style="--accent:var(--p-green)"><div class="slabel">Resolved</div><div class="sval">'+myIssues.filter(function(i){return i.status==="resolved";}).length+'</div></div>'
    +'<div class="stat-card" style="--accent:var(--p-orange)"><div class="slabel">Today\'s Tasks</div><div class="sval">'+dailyTasks.length+'</div></div>';

  // Attendance check-in
  document.getElementById("sp-attendance").innerHTML='<div style="display:flex;align-items:center;gap:12px;padding:12px 0"><button class="btn '+(amCheckedIn?"btn-grn":"btn-gold")+'" onclick="staffCheckIn()">'+(amCheckedIn?"\u2705 Checked In":"Check In Now")+'</button>'+(amCheckedIn?'<button class="btn btn-out" onclick="staffCheckOut()">Check Out</button>':'')+'<span style="font-size:.82rem;color:var(--muted)">'+fdateFull(today())+'</span></div>';

  // Tasks
  document.getElementById("sp-tasks").innerHTML=myIssues.filter(function(i){return i.status!=="resolved";}).length?myIssues.filter(function(i){return i.status!=="resolved";}).map(function(i){return '<div class="mcard"><div class="mcard-hdr"><div><div style="font-weight:600">'+i.title+'</div><div style="font-size:.75rem;color:var(--muted)">'+i.cat+' \u00B7 '+(i.room||"General")+' \u00B7 <span style="color:'+(i.pri==="high"?"var(--p-red)":"var(--muted)")+'">'+i.pri.toUpperCase()+'</span></div></div><button class="btn btn-grn btn-sm" onclick="staffResolve(\''+i.id+'\')">Done</button></div>'+(i.desc?'<div style="font-size:.82rem;color:var(--muted);margin-top:4px">'+i.desc+'</div>':'')+'</div>';}).join(''):'<div style="text-align:center;padding:40px;color:var(--muted)">No tasks</div>';

  // Daily tasks with claim (Feature 32)
  document.getElementById("sp-daily").innerHTML=dailyTasks.length?dailyTasks.map(function(dt){
    var claimed=dt.claimedBy?true:false;var isMine=dt.claimedBy===currentUser.name;
    return '<div class="mcard"><div class="mcard-hdr"><div><div style="font-weight:600">'+dt.title+'</div><div style="font-size:.73rem;color:var(--muted)">'+(claimed?'\uD83D\uDC77 Being handled by: '+dt.claimedBy+(isMine?" (You)":""):"Unclaimed")+'</div></div><div style="display:flex;gap:4px">'+(claimed?'':"<button class=\"btn btn-gold btn-sm\" onclick=\"staffClaimTask('"+dt.id+"')\">I\'m On It</button>")+(isMine?'<button class="btn btn-grn btn-sm" onclick="staffCompleteTask(\''+dt.id+'\')">Done</button>':'')+'</div></div></div>';
  }).join(''):'<div style="text-align:center;padding:30px;color:var(--muted)">No daily tasks for today</div>';

  // Incidents (Feature 34)
  document.getElementById("sp-incidents").innerHTML='<div class="hint-box">\u26A0 Priority: Report incidents physically to management first. Use this form as a secondary record.</div>';

  // Staff directory (Feature 37)
  var allStaff=dbGet(hk(hid,"staff"));
  document.getElementById("sp-directory").innerHTML=allStaff.map(function(s){return '<div class="oi"><div><div style="font-weight:600">'+s.name+(s.teamRole?' <span class="badge bb" style="font-size:.6rem">'+s.teamRole+'</span>':'')+'</div><div style="font-size:.73rem;color:var(--muted)">'+s.role+'</div></div></div>';}).join('')||'<div style="color:var(--muted);text-align:center;padding:16px">No staff listed</div>';

  // Notices
  document.getElementById("sp-notices").innerHTML=notices.slice(0,5).map(function(n){return '<div style="padding:6px 0;border-bottom:1px solid var(--bd);font-size:.82rem"><div style="font-weight:500;color:var(--text)">'+(n.pinned?"\uD83D\uDCCC ":"")+n.title+'</div><div style="font-size:.68rem;color:var(--muted)">'+fdate(n.date)+'</div></div>';}).join('')||'<div style="color:var(--muted);padding:16px;text-align:center">No notices</div>';

  // Inventory requests (Feature 35)
  var invReqs=dbGet(hk(hid,"inv_requests")).filter(function(r){return r.staffId===(currentUser.staffId||currentUser.name);});
  document.getElementById("sp-inventory").innerHTML=invReqs.length?invReqs.map(function(r){return '<div class="oi"><div>'+r.item+'</div><span class="badge '+(r.status==="approved"?"bg":r.status==="rejected"?"br":"bo")+'">'+r.status+'</span></div>';}).join(''):'<div style="color:var(--muted);font-size:.82rem">No requests yet</div>';

  // Salary view (Feature 36)
  var myStaff=allStaff.find(function(s){return s.name===currentUser.name;});
  // Clock log for staff
  var clockLog=[];
  for(var ci=0;ci<7;ci++){var cd=new Date();cd.setDate(cd.getDate()-ci);var cds=cd.getFullYear()+"-"+String(cd.getMonth()+1).padStart(2,"0")+"-"+String(cd.getDate()).padStart(2,"0");var ckey="staff_att_"+cds.replace(/-/g,"");var catt=dbGetO(hk(hid,ckey));if(catt[currentUser.name]){var ce=catt[currentUser.name];clockLog.push({date:cds,inT:ce.in||ce,outT:ce.out||null});}}
  document.getElementById("sp-clock-log").innerHTML=clockLog.length?clockLog.map(function(l){var inT2=l.inT?new Date(l.inT).toLocaleTimeString("en-PK",{hour:"2-digit",minute:"2-digit"}):"\u2014";var outT2=l.outT?new Date(l.outT).toLocaleTimeString("en-PK",{hour:"2-digit",minute:"2-digit"}):"Still In";return '<div class="oi"><div>'+fdate(l.date)+'</div><div>In: '+inT2+' &middot; Out: '+outT2+'</div></div>';}).join(''):'<div style="color:var(--muted);font-size:.82rem">No clock records</div>';
  document.getElementById("sp-salary").innerHTML=myStaff&&myStaff.salary?'<div class="ht-pr"><span style="color:var(--muted)">Monthly Salary</span><span style="font-weight:600;color:var(--p-green)">Rs. '+mFmt(myStaff.salary)+'</span></div><div class="ht-pr"><span style="color:var(--muted)">Role</span><span>'+myStaff.role+(myStaff.teamRole?" \u00B7 "+myStaff.teamRole:"")+'</span></div>':'<div style="color:var(--muted);font-size:.82rem">Salary info not available. Contact your manager.</div>';
}
function staffResolve(id){var hid=currentUser.hid,arr=dbGet(hk(hid,"maint")),i=arr.find(function(x){return x.id===id;});if(i){i.status="resolved";i.resolvedOn=today();dbSet(hk(hid,"maint"),arr);addNotif(currentUser.name+" resolved: "+i.title,"manager");mToast("Resolved","ok");renderStaffPortal();}}
function staffCheckIn(){var hid=currentUser.hid;var key="staff_att_"+today().replace(/-/g,"");var att=dbGetO(hk(hid,key));att[currentUser.name]={in:new Date().toISOString()};dbSetO(hk(hid,key),att);addNotif(currentUser.name+" clocked in","manager");mToast("Checked in","ok");renderStaffPortal();}
function staffCheckOut(){var hid=currentUser.hid;var key="staff_att_"+today().replace(/-/g,"");var att=dbGetO(hk(hid,key));if(att[currentUser.name]){att[currentUser.name].out=new Date().toISOString();}dbSetO(hk(hid,key),att);addNotif(currentUser.name+" clocked out","manager");mToast("Checked out","ok");renderStaffPortal();}
function staffClaimTask(id){var hid=currentUser.hid;var tasks=dbGet(hk(hid,"daily_tasks"));var t=tasks.find(function(x){return x.id===id;});if(t){t.claimedBy=currentUser.name;dbSet(hk(hid,"daily_tasks"),tasks);mToast("Claimed","ok");renderStaffPortal();}}
function staffCompleteTask(id){var hid=currentUser.hid;var tasks=dbGet(hk(hid,"daily_tasks"));var t=tasks.find(function(x){return x.id===id;});if(t){t.status="done";t.doneOn=new Date().toISOString();dbSet(hk(hid,"daily_tasks"),tasks);mToast("Completed","ok");renderStaffPortal();}}
function staffReportIncident(){
  var title=document.getElementById("sp-inc-title").value.trim();var desc=document.getElementById("sp-inc-desc").value.trim();
  if(!title){mToast("Title required","err");return;}
  var hid=currentUser.hid;var arr=dbGet(hk(hid,"incidents"));
  arr.push({id:dbId(),title:title,desc:desc,reporter:currentUser.name,date:new Date().toISOString(),physicalReport:false});
  dbSet(hk(hid,"incidents"),arr);
  addNotif("Incident reported by "+currentUser.name+": "+title,"manager");
  document.getElementById("sp-inc-title").value="";document.getElementById("sp-inc-desc").value="";
  mToast("Incident recorded. Please also report physically if possible.","ok");
}
function staffRequestSupply(){
  openMM("staff-supply-req");
}
function staffDoSupplyReq(){
  var item=document.getElementById("sp-supply-item").value;
  var notes=document.getElementById("sp-supply-notes").value.trim();
  if(!item){mToast("Select an item","err");return;}
  if(notes)item=item+" - "+notes;
  var hid=currentUser.hid;var reqs=dbGet(hk(hid,"inv_requests"));
  reqs.push({id:dbId(),item:item,staffId:currentUser.staffId||currentUser.name,staffName:currentUser.name,status:"pending",date:today()});
  dbSet(hk(hid,"inv_requests"),reqs);
  addNotif(currentUser.name+" requested supply: "+item,"manager");
  closeMM("staff-supply-req");mToast("Supply request submitted","ok");renderStaffPortal();
}

// ÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚Â
// FINANCE PORTAL
// ÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚Â
function renderFinancePortal(){
  if(!currentUser||currentUser.role!=="finance")return;
  var totalRev=0,totalExp=0,totalBills=0,totalDeposits=0;
  var groups=dbGet("hostel_groups");
  HOSTELS.filter(Boolean).forEach(function(h){
    var pays=dbGet(hk(h.id,"pays")).filter(function(p){return p.month===curM()&&p.status==="paid";});
    totalRev+=pays.reduce(function(s,p){return s+p.amount;},0);
    var exps=dbGet(hk(h.id,"expenses")).filter(function(e){return (e.date||"").substring(0,7)===curM();});
    totalExp+=exps.reduce(function(s,e){return s+e.amount;},0);
    totalBills+=dbGet(hk(h.id,"bills")).filter(function(b){return b.status!=="paid";}).reduce(function(s,b){return s+b.amount;},0);
    totalDeposits+=dbGet(hk(h.id,"tenants")).filter(function(t){return t.status==="active";}).reduce(function(s,t){return s+(t.deposit||0);},0);
  });
  var net=totalRev-totalExp;
  // Stats
  document.getElementById("fp-stats").innerHTML=""
    +'<div class="stat-card" style="--accent:var(--p-green)"><div class="slabel">Revenue ('+mlabel(curM())+')</div><div class="sval" style="font-size:1.1rem">Rs. '+mFmt(totalRev)+'</div></div>'
    +'<div class="stat-card" style="--accent:var(--p-red)"><div class="slabel">Expenses</div><div class="sval" style="font-size:1.1rem">Rs. '+mFmt(totalExp)+'</div></div>'
    +'<div class="stat-card" style="--accent:var(--p-orange)"><div class="slabel">Unpaid Bills</div><div class="sval" style="font-size:1.1rem">Rs. '+mFmt(totalBills)+'</div></div>'
    +'<div class="stat-card" style="--accent:'+(net>=0?"var(--p-green)":"var(--p-red)")+'"><div class="slabel">Net P&L</div><div class="sval" style="font-size:1.1rem">'+(net>=0?"+":"")+'Rs. '+mFmt(net)+'</div></div>'
    +'<div class="stat-card" style="--accent:var(--p-blue)"><div class="slabel">Deposit Liability</div><div class="sval" style="font-size:1.1rem">Rs. '+mFmt(totalDeposits)+'</div></div>';

  // Collection efficiency (Feature 40)
  var effHtml=HOSTELS.filter(Boolean).map(function(h){
    var tenants=dbGet(hk(h.id,"tenants")).filter(function(t){return t.status==="active";});
    var pays=dbGet(hk(h.id,"pays")).filter(function(p){return p.month===curM()&&p.status==="paid";});
    var paidCount=new Set(pays.map(function(p){return p.tid;})).size;
    var eff=tenants.length?Math.round(paidCount/tenants.length*100):100;
    return '<div class="oi"><div><div style="font-weight:600;font-size:.83rem">'+h.emoji+' '+h.short+'</div><div style="font-size:.72rem;color:var(--muted)">'+paidCount+'/'+tenants.length+' paid</div></div><div style="text-align:right"><div style="font-family:var(--mono);color:'+(eff>=80?"var(--p-green)":eff>=50?"var(--p-orange)":"var(--p-red)")+'">'+eff+'%</div></div></div>';
  }).join('');
  document.getElementById("fp-efficiency").innerHTML=effHtml;

  // Per-hostel breakdown
  document.getElementById("fp-breakdown").innerHTML=HOSTELS.filter(Boolean).map(function(h){
    var pays=dbGet(hk(h.id,"pays")).filter(function(p){return p.month===curM()&&p.status==="paid";});
    var rev=pays.reduce(function(s,p){return s+p.amount;},0);
    var exps=dbGet(hk(h.id,"expenses")).filter(function(e){return (e.date||"").substring(0,7)===curM();});
    var exp=exps.reduce(function(s,e){return s+e.amount;},0);
    var tenants=dbGet(hk(h.id,"tenants")).filter(function(t){return t.status==="active";}).length;
    var group=groups.find(function(g){return g.hostels&&g.hostels.indexOf(h.id)>=0;});
    return '<div class="mcard"><div class="mcard-hdr"><div><div style="font-weight:600">'+h.emoji+' '+h.name+(group?' <span class="badge bb" style="font-size:.6rem">'+group.name+'</span>':'')+'</div><div style="font-size:.75rem;color:var(--muted)">'+tenants+' tenants</div></div><div style="text-align:right"><div style="color:var(--p-green);font-family:var(--mono)">+Rs. '+mFmt(rev)+'</div><div style="color:var(--p-red);font-family:var(--mono);font-size:.8rem">-Rs. '+mFmt(exp)+'</div><div style="font-family:var(--mono);font-size:.78rem;color:'+(rev-exp>=0?"var(--p-green)":"var(--p-red)")+';margin-top:2px">Net: '+(rev-exp>=0?"+":"")+'Rs. '+mFmt(rev-exp)+'</div></div></div></div>';
  }).join('');

  // Overdue aging (Feature 41)
  var aging={d15:0,d30:0,d30plus:0};
  HOSTELS.filter(Boolean).forEach(function(h){
    var tenants=dbGet(hk(h.id,"tenants")).filter(function(t){return t.status==="active";});
    var paidIds={};dbGet(hk(h.id,"pays")).filter(function(p){return p.month===curM()&&p.status==="paid";}).forEach(function(p){paidIds[p.tid]=true;});
    tenants.forEach(function(t){
      if(!paidIds[t.id]){
        var dayOfMonth=new Date().getDate();
        if(dayOfMonth<=15)aging.d15+=t.rent;
        else if(dayOfMonth<=30)aging.d30+=t.rent;
        else aging.d30plus+=t.rent;
      }
    });
  });
  document.getElementById("fp-aging").innerHTML='<div class="oi"><div style="font-weight:600;color:var(--p-orange)">0-15 days</div><span style="font-family:var(--mono)">Rs. '+mFmt(aging.d15)+'</span></div><div class="oi"><div style="font-weight:600;color:var(--p-red)">15-30 days</div><span style="font-family:var(--mono)">Rs. '+mFmt(aging.d30)+'</span></div><div class="oi"><div style="font-weight:600;color:var(--p-red)">30+ days</div><span style="font-family:var(--mono)">Rs. '+mFmt(aging.d30plus)+'</span></div>';

  // Expense categories (Feature 42)
  var catTotals={};
  HOSTELS.filter(Boolean).forEach(function(h){
    dbGet(hk(h.id,"expenses")).filter(function(e){return (e.date||"").substring(0,7)===curM();}).forEach(function(e){catTotals[e.cat]=(catTotals[e.cat]||0)+e.amount;});
  });
  document.getElementById("fp-categories").innerHTML=Object.keys(catTotals).length?Object.keys(catTotals).sort(function(a,b){return catTotals[b]-catTotals[a];}).map(function(c){var pct=totalExp?Math.round(catTotals[c]/totalExp*100):0;return '<div class="oi"><div><div style="font-weight:600;font-size:.83rem">'+c+'</div><div style="font-size:.72rem;color:var(--muted)">'+pct+'%</div></div><span style="font-family:var(--mono);color:var(--p-red)">Rs. '+mFmt(catTotals[c])+'</span></div>';}).join(''):'<div style="text-align:center;padding:20px;color:var(--muted)">No expenses this month</div>';

  // Month comparison (Feature 38)
  renderFinanceComparison();
}
function renderFinanceComparison(){
  var period=(document.getElementById("fp-period")||{}).value||"1";
  var months=parseInt(period);
  var now=new Date();
  var data=[];
  for(var i=months-1;i>=0;i--){
    var d=new Date(now.getFullYear(),now.getMonth()-i,1);
    var ym=d.getFullYear()+"-"+String(d.getMonth()+1).padStart(2,"0");
    var rev=0,exp=0;
    HOSTELS.filter(Boolean).forEach(function(h){
      rev+=dbGet(hk(h.id,"pays")).filter(function(p){return p.month===ym&&p.status==="paid";}).reduce(function(s,p){return s+p.amount;},0);
      exp+=dbGet(hk(h.id,"expenses")).filter(function(e){return (e.date||"").substring(0,7)===ym;}).reduce(function(s,e){return s+e.amount;},0);
    });
    data.push({label:mlabel(ym),rev:rev,exp:exp,net:rev-exp});
  }
  var el=document.getElementById("fp-comparison");if(!el)return;
  el.innerHTML='<div class="tw"><table><thead><tr><th>Month</th><th>Revenue</th><th>Expenses</th><th>Net P&L</th></tr></thead><tbody>'+data.map(function(d){return '<tr><td>'+d.label+'</td><td style="color:var(--p-green)">Rs. '+mFmt(d.rev)+'</td><td style="color:var(--p-red)">Rs. '+mFmt(d.exp)+'</td><td style="color:'+(d.net>=0?"var(--p-green)":"var(--p-red)")+'">'+(d.net>=0?"+":"")+'Rs. '+mFmt(d.net)+'</td></tr>';}).join('')+'</tbody></table></div>';
}

// ÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚Â CUSTOM HOSTELS ÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚Â
function loadCustomHostels(){
  try{while(HOSTELS.length>12)HOSTELS.pop();while(MGRS.length>12)MGRS.pop();
  var saved=JSON.parse(localStorage.getItem("lbh_custom_hostels")||"[]");
  saved.forEach(function(h){h.isCustom=true;if(!HOSTELS.find(function(x){return x&&x.id===h.id;})){HOSTELS.push(h);MGRS.push({hid:h.id,user:h.mgUser,pass:h.mgPass,name:h.owner});HPFX[h.id]=h.prefix||"CST";RCFG[h.id]=[[4,10]];}});}catch(e){}
}

// ÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚Â GLOBAL SEARCH (Feature 49) ÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚Â
function globalSearch(q){
  if(!q||q.length<2||!currentUser)return;
  var results=[];
  if(currentUser.role==="manager"&&currentUser.hid){
    var hid=currentUser.hid;
    dbGet(hk(hid,"tenants")).forEach(function(t){if(t.name.toLowerCase().indexOf(q)>=0||t.tid.toLowerCase().indexOf(q)>=0||t.phone.indexOf(q)>=0)results.push({type:"Tenant",label:t.name+" ("+t.tid+")",action:"mViewTen('"+t.id+"')"});});
    dbGet(hk(hid,"maint")).forEach(function(i){if(i.title.toLowerCase().indexOf(q)>=0)results.push({type:"Issue",label:i.title,action:""});});
  }
  var panel=document.getElementById("gsearch-results");if(!panel)return;
  if(!results.length){panel.classList.remove("open");return;}
  panel.innerHTML=results.slice(0,8).map(function(r){return '<div class="gsr-item" onclick="'+r.action+'"><div class="gsr-type">'+r.type+'</div><div>'+r.label+'</div></div>';}).join('');
  panel.classList.add("open");
}

// ÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚Â INIT ÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚Â
