// Finance tab switching
function switchFTab(tab){
  ["fp-overview","fp-perhostel","fp-charts"].forEach(function(t){
    var el=document.getElementById(t);if(el)el.style.display=t===tab?"block":"none";
    document.querySelectorAll(".mtab").forEach(function(b){if(b.dataset.tab)b.classList.toggle("active",b.dataset.tab===tab);});
  });
  if(tab==="fp-perhostel"){renderFPPerHostelSel();renderFPPerHostel();}
  if(tab==="fp-charts")renderFPCharts();
}
function renderFPPerHostelSel(){
  var sel=document.getElementById("fp-hostel-sel");if(!sel)return;
  sel.innerHTML='<option value="">All Hostels</option>';
  HOSTELS.filter(Boolean).forEach(function(h){sel.innerHTML+='<option value="'+h.id+'">'+h.emoji+' '+h.name+'</option>';});
}
function renderFPPerHostel(){
  var hid=document.getElementById("fp-hostel-sel").value;
  var list=hid?HOSTELS.filter(function(h){return h&&h.id==hid;}):HOSTELS.filter(Boolean);
  var el=document.getElementById("fp-ph-content");if(!el)return;
  el.innerHTML=list.map(function(h){
    var tenants=dbGet(hk(h.id,"tenants")).filter(function(t){return t.status==="active";});
    var rooms=dbGet(hk(h.id,"rooms"));var totalBeds=rooms.reduce(function(s,r){return s+r.cap;},0);
    var pays=dbGet(hk(h.id,"pays")).filter(function(p){return p.month===curM()&&p.status==="paid";});
    var rev=pays.reduce(function(s,p){return s+p.amount;},0);
    var exps=dbGet(hk(h.id,"expenses")).filter(function(e){return (e.date||"").substring(0,7)===curM();});
    var exp=exps.reduce(function(s,e){return s+e.amount;},0);
    var paidCount=new Set(pays.map(function(p){return p.tid;})).size;
    var eff=tenants.length?Math.round(paidCount/tenants.length*100):100;
    var occ=totalBeds?Math.round(tenants.length/totalBeds*100):0;
    var allPays=dbGet(hk(h.id,"pays"));
    return '<div class="dc" style="margin-bottom:16px"><div class="dc-title">'+h.emoji+' '+h.name+' &mdash; '+h.area+'</div><div style="display:grid;grid-template-columns:repeat(5,1fr);gap:10px;margin-bottom:12px"><div class="stat-card" style="--accent:var(--p-blue);padding:10px 12px"><div class="slabel" style="font-size:.62rem">Tenants</div><div class="sval" style="font-size:1.1rem">'+tenants.length+'/'+totalBeds+'</div></div><div class="stat-card" style="--accent:var(--p-green);padding:10px 12px"><div class="slabel" style="font-size:.62rem">Revenue</div><div class="sval" style="font-size:1rem">Rs. '+mFmt(rev)+'</div></div><div class="stat-card" style="--accent:var(--p-red);padding:10px 12px"><div class="slabel" style="font-size:.62rem">Expenses</div><div class="sval" style="font-size:1rem">Rs. '+mFmt(exp)+'</div></div><div class="stat-card" style="--accent:var(--p-orange);padding:10px 12px"><div class="slabel" style="font-size:.62rem">Collection</div><div class="sval" style="font-size:1.1rem">'+eff+'%</div></div><div class="stat-card" style="--accent:var(--gold);padding:10px 12px"><div class="slabel" style="font-size:.62rem">Occupancy</div><div class="sval" style="font-size:1.1rem">'+occ+'%</div></div></div><div class="tw"><table><thead><tr><th>Tenant</th><th>Rent</th><th>Status</th><th>Paid</th></tr></thead><tbody>'+tenants.map(function(t){var tp=allPays.filter(function(p){return p.tid===t.id&&p.month===curM()&&p.status==="paid";});var paid=tp.reduce(function(s,p){return s+p.amount;},0);return "<tr><td>"+t.name+"</td><td>Rs. "+mFmt(t.rent)+"</td><td>"+(paid>=t.rent?"<span class=\"badge bg\">Paid</span>":paid>0?"<span class=\"badge bo\">Partial</span>":"<span class=\"badge br\">Unpaid</span>")+"</td><td>Rs. "+mFmt(paid)+"</td></tr>";}).join("")+'</tbody></table></div></div>';
  }).join('');
}
function renderFPCharts(){
  // Revenue bar chart
  var data=HOSTELS.filter(Boolean).map(function(h){
    var rev=dbGet(hk(h.id,"pays")).filter(function(p){return p.month===curM()&&p.status==="paid";}).reduce(function(s,p){return s+p.amount;},0);
    return {name:h.short,rev:rev,emoji:h.emoji};
  });
  var maxRev=Math.max.apply(null,data.map(function(d){return d.rev;}))||1;
  document.getElementById("fp-chart-rev").innerHTML='<div style="display:flex;align-items:flex-end;gap:4px;height:170px">'+data.map(function(d){
    var h=Math.max(4,Math.round(d.rev/maxRev*150));
    return '<div style="flex:1;text-align:center"><div style="background:var(--p-green);border-radius:3px 3px 0 0;height:'+h+'px;margin:0 auto;width:100%;max-width:40px" title="Rs. '+mFmt(d.rev)+'"></div><div style="font-size:.58rem;color:var(--muted);margin-top:3px;white-space:nowrap;overflow:hidden">'+d.name+'</div></div>';
  }).join('')+'</div>';

  // Expense pie chart (simple horizontal bars)
  var catTotals={};var totalExp=0;
  HOSTELS.filter(Boolean).forEach(function(h){
    dbGet(hk(h.id,"expenses")).filter(function(e){return (e.date||"").substring(0,7)===curM();}).forEach(function(e){catTotals[e.cat]=(catTotals[e.cat]||0)+e.amount;totalExp+=e.amount;});
  });
  var colors={"Utilities":"#4A9EFF","Maintenance":"#FF9A3C","Salary":"#3DD68C","Supplies":"#9A6AFF","Other":"#FF5C5C"};
  document.getElementById("fp-chart-exp").innerHTML=Object.keys(catTotals).length?Object.keys(catTotals).sort(function(a,b){return catTotals[b]-catTotals[a];}).map(function(c){
    var pct=totalExp?Math.round(catTotals[c]/totalExp*100):0;
    return '<div style="margin-bottom:8px"><div style="display:flex;justify-content:space-between;font-size:.76rem;color:var(--text);margin-bottom:2px"><span>'+c+'</span><span>'+pct+'% (Rs. '+mFmt(catTotals[c])+')</span></div><div style="height:8px;background:var(--sf2);border-radius:4px;overflow:hidden"><div style="height:100%;width:'+pct+'%;background:'+(colors[c]||"var(--gold)")+';border-radius:4px"></div></div></div>';
  }).join(''):'<div style="text-align:center;padding:30px;color:var(--muted)">No expenses</div>';

  // Revenue trend
  var now=new Date();var months=[];
  for(var i=5;i>=0;i--){var d=new Date(now.getFullYear(),now.getMonth()-i,1);var ym=d.getFullYear()+"-"+String(d.getMonth()+1).padStart(2,"0");var r=0;HOSTELS.filter(Boolean).forEach(function(h){r+=dbGet(hk(h.id,"pays")).filter(function(p){return p.month===ym&&p.status==="paid";}).reduce(function(s,p){return s+p.amount;},0);});months.push({label:mlabel(ym),rev:r});}
  var maxT=Math.max.apply(null,months.map(function(m){return m.rev;}))||1;
  document.getElementById("fp-chart-trend").innerHTML='<div style="display:flex;align-items:flex-end;gap:6px;height:150px">'+months.map(function(m){var h=Math.max(4,Math.round(m.rev/maxT*130));return '<div style="flex:1;text-align:center"><div style="background:var(--gold);border-radius:3px 3px 0 0;height:'+h+'px;margin:0 auto;width:100%;max-width:50px" title="Rs. '+mFmt(m.rev)+'"></div><div style="font-size:.65rem;color:var(--muted);margin-top:4px">'+m.label+'</div></div>';}).join('')+'</div>';

  // Occupancy bars
  document.getElementById("fp-chart-occ").innerHTML=HOSTELS.filter(Boolean).map(function(h){
    var tenants=dbGet(hk(h.id,"tenants")).filter(function(t){return t.status==="active";}).length;
    var rooms=dbGet(hk(h.id,"rooms"));var totalBeds=rooms.reduce(function(s,r){return s+r.cap;},0);
    var occ=totalBeds?Math.round(tenants/totalBeds*100):0;
    return '<div style="margin-bottom:6px"><div style="display:flex;justify-content:space-between;font-size:.76rem;color:var(--text);margin-bottom:2px"><span>'+h.short+'</span><span>'+occ+'% ('+tenants+'/'+totalBeds+')</span></div><div style="height:6px;background:var(--sf2);border-radius:3px;overflow:hidden"><div style="height:100%;width:'+occ+'%;background:'+(occ>=80?"var(--p-green)":occ>=50?"var(--p-orange)":"var(--p-red)")+';border-radius:3px"></div></div></div>';
  }).join('');

  // Collection bars
  document.getElementById("fp-chart-coll").innerHTML=HOSTELS.filter(Boolean).map(function(h){
    var tenants=dbGet(hk(h.id,"tenants")).filter(function(t){return t.status==="active";});
    var paidIds={};dbGet(hk(h.id,"pays")).filter(function(p){return p.month===curM()&&p.status==="paid";}).forEach(function(p){paidIds[p.tid]=true;});
    var eff=tenants.length?Math.round(Object.keys(paidIds).length/tenants.length*100):100;
    return '<div style="margin-bottom:6px"><div style="display:flex;justify-content:space-between;font-size:.76rem;color:var(--text);margin-bottom:2px"><span>'+h.short+'</span><span>'+eff+'%</span></div><div style="height:6px;background:var(--sf2);border-radius:3px;overflow:hidden"><div style="height:100%;width:'+eff+'%;background:'+(eff>=80?"var(--p-green)":eff>=50?"var(--p-orange)":"var(--p-red)")+';border-radius:3px"></div></div></div>';
  }).join('');
}
// Staff check-in/out log for manager
function renderMStaffClock(){
  var hid=currentUser.hid;var staff=dbGet(hk(hid,"staff"));
  var log=[];
  // Collect last 7 days
  for(var i=0;i<7;i++){
    var d=new Date();d.setDate(d.getDate()-i);
    var ds=d.getFullYear()+"-"+String(d.getMonth()+1).padStart(2,"0")+"-"+String(d.getDate()).padStart(2,"0");
    var key="staff_att_"+ds.replace(/-/g,"");
    var att=dbGetO(hk(hid,key));
    Object.keys(att).forEach(function(sid){
      var entry=att[sid];
      log.push({staffName:sid,date:ds,inTime:entry.in||entry,outTime:entry.out||null});
    });
  }
  log.sort(function(a,b){return b.date.localeCompare(a.date)||b.inTime.localeCompare(a.inTime);});
  document.getElementById("m-staffclock-list").innerHTML=log.length?'<div class="tw"><table><thead><tr><th>Staff</th><th>Date</th><th>Clock In</th><th>Clock Out</th><th>Hours</th></tr></thead><tbody>'+log.map(function(l){
    var inT=l.inTime?new Date(l.inTime).toLocaleTimeString("en-PK",{hour:"2-digit",minute:"2-digit"}):"\u2014";
    var outT=l.outTime?new Date(l.outTime).toLocaleTimeString("en-PK",{hour:"2-digit",minute:"2-digit"}):"Still In";
    var hrs=l.inTime&&l.outTime?((new Date(l.outTime)-new Date(l.inTime))/3600000).toFixed(1)+"h":"\u2014";
    return "<tr><td style=\"font-weight:600\">"+l.staffName+"</td><td>"+fdate(l.date)+"</td><td>"+inT+"</td><td>"+outT+"</td><td>"+hrs+"</td></tr>";
  }).join("")+'</tbody></table></div>':'<div style="text-align:center;padding:40px;color:var(--muted)">No clock records found</div>';
}
// All-months payment view
function renderMPayAll(){
  var hid=currentUser.hid;var q=(document.getElementById("mp-allq")||{}).value||"";
  var allPays=dbGet(hk(hid,"pays")).sort(function(a,b){return b.date.localeCompare(a.date);});
  if(q){q=q.toLowerCase();allPays=allPays.filter(function(p){return p.tname.toLowerCase().indexOf(q)>=0;});}
  document.getElementById("mp-all-tbody").innerHTML=allPays.length?allPays.slice(0,100).map(function(p){
    return "<tr><td style=\"font-weight:600\">"+p.tname+"</td><td>"+mlabel(p.month)+"</td><td><span class=\"badge "+(PBDGS[p.ptype||"regular"]||"bgold")+"\">"+PLBLS[p.ptype||"regular"]+"</span></td><td style=\"color:var(--p-green)\">Rs. "+mFmt(p.amount)+"</td><td>"+fdate(p.date)+"</td><td><span class=\"badge bgold\">"+p.method+"</span></td></tr>";
  }).join(""):"<tr><td colspan=\"6\" style=\"text-align:center;padding:40px;color:var(--muted)\">No payments</td></tr>";
}


// ÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚Â WEBSITE MANAGEMENT TAB ÃƒÂ¢Ã¢â‚¬Â¢Ã‚ÂÃƒÂ¢Ã¢â‚¬Â¢Ã‚Â
function renderMWebsite(){
  var hid=currentUser.hid;var h=HOSTELS.find(function(x){return x&&x.id===hid;});if(!h)return;
  // Populate fields
  document.getElementById("ws-name").value=h.name;
  document.getElementById("ws-area").value=h.area;
  document.getElementById("ws-loc").value=h.loc;
  document.getElementById("ws-phone").value=h.phone;
  document.getElementById("ws-wa").value=h.wa||"";
  document.getElementById("ws-owner").value=h.owner;
  document.getElementById("ws-desc").value=h.desc||"";
  document.getElementById("ws-from").value=h.from;
  document.getElementById("ws-cap").value=h.cap;
  document.getElementById("ws-avail").value=h.avail;
  document.getElementById("ws-availS").value=h.availS||"available";
  document.getElementById("ws-meals").value=h.meals?"true":"false";
  // Banner
  var cfg=dbGetO(hk(hid,"config"));
  document.getElementById("ws-banner").value=cfg.webBanner||"";
  // Rooms
  document.getElementById("ws-rooms").innerHTML=h.rooms.map(function(r,i){
    return '<div style="display:flex;gap:6px;align-items:center;margin-bottom:6px;padding:8px;background:var(--sf2);border-radius:6px"><div style="flex:1"><div style="font-weight:600;font-size:.83rem;color:var(--text)">'+r.type+'</div><div style="font-size:.73rem;color:var(--muted)">'+r.count+' &middot; Rs. '+fmt(r.price)+'/mo</div></div><button class="btn btn-out btn-sm" onclick="mEditWebRoom('+i+')">Edit</button><button class="btn btn-red btn-sm" onclick="mDelWebRoom('+i+')">Del</button></div>';
  }).join('')||'<div style="color:var(--muted);font-size:.82rem">No room types defined</div>';
  // Amenities
  document.getElementById("ws-amenities").innerHTML=h.amenities.map(function(a,i){
    return '<span style="display:inline-flex;align-items:center;gap:4px;background:var(--sf2);border:1px solid var(--bd);border-radius:100px;padding:4px 10px;font-size:.76rem;color:var(--text);margin:3px">'+a[0]+' '+a[1]+' <button onclick="mDelWebAmenity('+i+')" style="background:none;border:none;color:var(--p-red);cursor:pointer;font-size:.8rem">&times;</button></span>';
  }).join('');
  // Tags
  document.getElementById("ws-tags").innerHTML=h.tagLbls.map(function(t,i){
    return '<span style="display:inline-flex;align-items:center;gap:4px;background:var(--sf2);border:1px solid var(--bd);border-radius:100px;padding:4px 10px;font-size:.76rem;color:var(--text);margin:3px">'+t+' <button onclick="mDelWebTag('+i+')" style="background:none;border:none;color:var(--p-red);cursor:pointer;font-size:.8rem">&times;</button></span>';
  }).join('');
}
function mSaveWebDetails(){
  var hid=currentUser.hid;var h=HOSTELS.find(function(x){return x&&x.id===hid;});if(!h)return;
  h.name=document.getElementById("ws-name").value.trim()||h.name;
  h.short=h.name.split(" ").slice(0,2).join(" ");
  h.area=document.getElementById("ws-area").value.trim()||h.area;
  h.loc=document.getElementById("ws-loc").value.trim()||h.loc;
  h.phone=document.getElementById("ws-phone").value.trim()||h.phone;
  h.wa=document.getElementById("ws-wa").value.trim()||h.wa;
  h.owner=document.getElementById("ws-owner").value.trim()||h.owner;
  h.desc=document.getElementById("ws-desc").value.trim()||h.desc;
  h.about=h.desc;
  buildHostelPages();filterHostels();mLog("Website details updated");mToast("Details saved & website updated","ok");
}
function mSaveWebPricing(){
  var hid=currentUser.hid;var h=HOSTELS.find(function(x){return x&&x.id===hid;});if(!h)return;
  h.from=parseInt(document.getElementById("ws-from").value)||h.from;
  h.cap=parseInt(document.getElementById("ws-cap").value)||h.cap;
  h.avail=parseInt(document.getElementById("ws-avail").value)||h.avail;
  h.availS=document.getElementById("ws-availS").value;
  buildHostelPages();filterHostels();mLog("Pricing updated");mToast("Pricing saved & website updated","ok");
}
function mSaveWebBanner(){
  var hid=currentUser.hid;var cfg=dbGetO(hk(hid,"config"));
  cfg.webBanner=document.getElementById("ws-banner").value.trim();
  dbSetO(hk(hid,"config"),cfg);mToast("Banner saved","ok");
}
function mSaveWebMeals(){
  var hid=currentUser.hid;var h=HOSTELS.find(function(x){return x&&x.id===hid;});if(!h)return;
  h.meals=document.getElementById("ws-meals").value==="true";
  if(h.meals&&h.tagLbls.indexOf("Meals")<0)h.tagLbls.push("Meals");
  if(!h.meals)h.tagLbls=h.tagLbls.filter(function(t){return t!=="Meals"&&t!=="2 Meals"&&t!=="3 Meals"&&t!=="Dinner";});
  buildHostelPages();filterHostels();mToast("Meals setting saved","ok");
}
function mAddWebAmenity(){
  var hid=currentUser.hid;var h=HOSTELS.find(function(x){return x&&x.id===hid;});if(!h)return;
  var name=document.getElementById("ws-new-amen").value.trim();if(!name)return;
  h.amenities.push(["\u2705",name]);
  document.getElementById("ws-new-amen").value="";
  buildHostelPages();filterHostels();renderMWebsite();mToast("Amenity added","ok");
}
function mDelWebAmenity(idx){
  var hid=currentUser.hid;var h=HOSTELS.find(function(x){return x&&x.id===hid;});if(!h)return;
  h.amenities.splice(idx,1);
  buildHostelPages();filterHostels();renderMWebsite();mToast("Removed","ok");
}
function mAddWebTag(){
  var hid=currentUser.hid;var h=HOSTELS.find(function(x){return x&&x.id===hid;});if(!h)return;
  var name=document.getElementById("ws-new-tag").value.trim();if(!name)return;
  if(h.tagLbls.indexOf(name)<0)h.tagLbls.push(name);
  if(h.tags.indexOf(name.toLowerCase())<0)h.tags.push(name.toLowerCase());
  document.getElementById("ws-new-tag").value="";
  buildHostelPages();filterHostels();renderMWebsite();mToast("Tag added","ok");
}
function mDelWebTag(idx){
  var hid=currentUser.hid;var h=HOSTELS.find(function(x){return x&&x.id===hid;});if(!h)return;
  h.tagLbls.splice(idx,1);
  buildHostelPages();filterHostels();renderMWebsite();
}
function mAddWebRoom(){
  var type=window.prompt?null:null;
  document.getElementById("mm-wr-type").value="";
  document.getElementById("mm-wr-count").value="";
  document.getElementById("mm-wr-price").value="";
  document.getElementById("mm-wr-feats").value="";
  openMM("add-web-room");
}
function mSaveWebRoom(){
  var hid=currentUser.hid;var h=HOSTELS.find(function(x){return x&&x.id===hid;});if(!h)return;
  var type=document.getElementById("mm-wr-type").value.trim();
  var count=document.getElementById("mm-wr-count").value.trim();
  var price=parseInt(document.getElementById("mm-wr-price").value);
  var feats=document.getElementById("mm-wr-feats").value.split(",").map(function(f){return f.trim();}).filter(Boolean);
  if(!type||!price){mToast("Type and price required","err");return;}
  h.rooms.push({type:type,count:count||"Standard",price:price,feats:feats.length?feats:["Included"]});
  buildHostelPages();filterHostels();closeMM("add-web-room");renderMWebsite();mToast("Room type added","ok");
}
function mEditWebRoom(idx){
  var hid=currentUser.hid;var h=HOSTELS.find(function(x){return x&&x.id===hid;});if(!h||!h.rooms[idx])return;
  var r=h.rooms[idx];
  document.getElementById("mm-wr-type").value=r.type;
  document.getElementById("mm-wr-count").value=r.count;
  document.getElementById("mm-wr-price").value=r.price;
  document.getElementById("mm-wr-feats").value=(r.feats||[]).join(", ");
  // Store edit index
  document.getElementById("mm-wr-idx").value=idx;
  openMM("add-web-room");
}
function mDelWebRoom(idx){
  var hid=currentUser.hid;var h=HOSTELS.find(function(x){return x&&x.id===hid;});if(!h)return;
  h.rooms.splice(idx,1);buildHostelPages();filterHostels();renderMWebsite();mToast("Removed","ok");
}

